"use client";

import { useCallback, useEffect, useRef, useState } from "react";

export type CameraPermissionState =
  | "unknown"
  | "prompt"
  | "granted"
  | "denied";

export interface UseCameraPermissionsResult {
  state: CameraPermissionState;
  /** Browser supports the Permissions API for "camera". */
  supported: boolean;
  /** Force a re-check (useful after explicit retry). */
  refresh: () => Promise<void>;
}

/**
 * Watches `navigator.permissions.query({ name: "camera" })` and auto-updates
 * on settings changes (Chrome / Firefox / Edge). Safari has no Permissions
 * API for camera; we expose `supported=false` and consumers fall back to
 * trying `getUserMedia` directly to discover the permission state.
 */
export function useCameraPermissions(): UseCameraPermissionsResult {
  const [state, setState] = useState<CameraPermissionState>("unknown");
  const [supported, setSupported] = useState(false);
  const statusRef = useRef<PermissionStatus | null>(null);

  const refresh = useCallback(async () => {
    if (typeof navigator === "undefined" || !navigator.permissions?.query) {
      setSupported(false);
      setState("unknown");
      return;
    }
    try {
      // `camera` is in the Permissions spec but TS lib.dom doesn't list it.
      const status = await navigator.permissions.query({
        name: "camera" as PermissionName,
      });
      statusRef.current = status;
      setSupported(true);
      setState(status.state as CameraPermissionState);
    } catch {
      // Safari throws TypeError for "camera"
      setSupported(false);
      setState("unknown");
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  useEffect(() => {
    const status = statusRef.current;
    if (!status) return;
    const handler = () => setState(status.state as CameraPermissionState);
    status.addEventListener("change", handler);
    return () => status.removeEventListener("change", handler);
  }, [supported]);

  return { state, supported, refresh };
}

"use client";

import { useCallback, useRef, useState } from "react";
import type { DrawingStroke } from "../types";

export interface UseDrawingStrokeOptions {
  color: string;
  brushSize: number;
  mode: "draw" | "erase";
  /** Fires once when the user lifts the pointer — receives the completed stroke. */
  onStrokeComplete: (stroke: DrawingStroke) => void;
}

export interface UseDrawingStrokeResult {
  /** In-progress stroke (rendered live until pointer-up). */
  currentStroke: DrawingStroke | null;
  /** Bind onto Stage pointer events when draw tool is active. */
  beginAt: (x: number, y: number) => void;
  extendTo: (x: number, y: number) => void;
  end: () => void;
  cancel: () => void;
}

/**
 * Pointer-frame collector for a single freehand stroke.
 *
 * The composer-editor wires Stage pointer events into beginAt/extendTo/end
 * when the draw tool is active. Each completed stroke is dispatched once via
 * `onStrokeComplete` — the parent records that as a single undo command (one
 * command per stroke, not one per pointer frame).
 */
export function useDrawingStroke(
  options: UseDrawingStrokeOptions,
): UseDrawingStrokeResult {
  const { color, brushSize, mode, onStrokeComplete } = options;
  const [currentStroke, setCurrentStroke] = useState<DrawingStroke | null>(
    null,
  );
  const strokeRef = useRef<DrawingStroke | null>(null);

  const beginAt = useCallback(
    (x: number, y: number) => {
      const id = `stroke-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
      const next: DrawingStroke = {
        id,
        points: [x, y],
        color,
        brushSize,
        mode,
      };
      strokeRef.current = next;
      setCurrentStroke(next);
    },
    [color, brushSize, mode],
  );

  const extendTo = useCallback((x: number, y: number) => {
    const s = strokeRef.current;
    if (!s) return;
    s.points.push(x, y);
    // Re-render — clone the points array so React notices.
    setCurrentStroke({ ...s, points: [...s.points] });
  }, []);

  const end = useCallback(() => {
    const s = strokeRef.current;
    strokeRef.current = null;
    setCurrentStroke(null);
    if (!s || s.points.length < 4) return; // ignore single-point taps
    onStrokeComplete(s);
  }, [onStrokeComplete]);

  const cancel = useCallback(() => {
    strokeRef.current = null;
    setCurrentStroke(null);
  }, []);

  return { currentStroke, beginAt, extendTo, end, cancel };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

export interface Command {
  do: () => void;
  undo: () => void;
  label?: string;
}

export interface UseHistoryOptions {
  /** Hard cap on undo depth. Oldest entries FIFO-evicted past this. Default 50. */
  capacity?: number;
  /** When true, Ctrl/Cmd+Z and Ctrl/Cmd+Shift+Z bind to undo/redo. */
  bindKeyboard?: boolean;
}

export interface UseHistoryResult {
  /** Run a command + push it onto the undo stack. Clears redo stack. */
  execute: (cmd: Command) => void;
  undo: () => void;
  redo: () => void;
  canUndo: boolean;
  canRedo: boolean;
  /** Drops both stacks (e.g., when the draft is replaced). */
  reset: () => void;
}

/**
 * Generic undo/redo command stack.
 *
 * Each command's `do()` is run on execute() and again on redo(); `undo()` is
 * run on undo. The hook does NOT mediate state — callers wrap their state
 * mutations into Command pairs.
 *
 * Drawing strokes record one command per completed stroke (not per pointer
 * frame). Text/sticker add/delete/move/transform record one command per
 * terminal action.
 */
export function useHistory(
  options: UseHistoryOptions = {},
): UseHistoryResult {
  const { capacity = 50, bindKeyboard = true } = options;
  const pastRef = useRef<Command[]>([]);
  const futureRef = useRef<Command[]>([]);
  const [, force] = useState(0);
  const tick = useCallback(() => force((n) => (n + 1) | 0), []);

  const execute = useCallback(
    (cmd: Command) => {
      cmd.do();
      pastRef.current.push(cmd);
      if (pastRef.current.length > capacity) {
        pastRef.current.shift();
      }
      futureRef.current = [];
      tick();
    },
    [capacity, tick],
  );

  const undo = useCallback(() => {
    const cmd = pastRef.current.pop();
    if (!cmd) return;
    cmd.undo();
    futureRef.current.push(cmd);
    tick();
  }, [tick]);

  const redo = useCallback(() => {
    const cmd = futureRef.current.pop();
    if (!cmd) return;
    cmd.do();
    pastRef.current.push(cmd);
    tick();
  }, [tick]);

  const reset = useCallback(() => {
    pastRef.current = [];
    futureRef.current = [];
    tick();
  }, [tick]);

  // Ctrl/Cmd+Z / Ctrl/Cmd+Shift+Z keyboard shortcuts.
  useEffect(() => {
    if (!bindKeyboard || typeof window === "undefined") return;
    const handler = (e: KeyboardEvent) => {
      const mod = e.ctrlKey || e.metaKey;
      if (!mod) return;
      if (e.key.toLowerCase() !== "z") return;
      // Don't hijack while typing in an input/textarea.
      const tgt = e.target as HTMLElement | null;
      if (
        tgt?.tagName === "INPUT" ||
        tgt?.tagName === "TEXTAREA" ||
        tgt?.isContentEditable
      ) {
        return;
      }
      e.preventDefault();
      if (e.shiftKey) redo();
      else undo();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [bindKeyboard, undo, redo]);

  return {
    execute,
    undo,
    redo,
    canUndo: pastRef.current.length > 0,
    canRedo: futureRef.current.length > 0,
    reset,
  };
}

"use client";

import { useCallback, useRef, useState } from "react";
import type Konva from "konva";

export type SelectableKind = "text" | "sticker" | "drawing";

export interface SelectedItem {
  kind: SelectableKind;
  id: string;
}

export interface UseKonvaSelectionResult {
  selected: SelectedItem | null;
  transformerRef: React.MutableRefObject<Konva.Transformer | null>;
  /** Select an overlay item and attach the transformer to its node. */
  select: (item: SelectedItem | null, node: Konva.Node | null) => void;
  /** Clear selection (Esc / click on background / draft replaced). */
  clear: () => void;
}

/**
 * Konva.Transformer attach/detach helper.
 *
 * C6 lands the hook surface only — there are no selectable items yet
 * (text/stickers/drawing land C8/C9/C10). Each tool wires its node into
 * `select(item, node)`; the hook calls Transformer.nodes([node]).
 */
export function useKonvaSelection(): UseKonvaSelectionResult {
  const [selected, setSelected] = useState<SelectedItem | null>(null);
  const transformerRef = useRef<Konva.Transformer | null>(null);

  const select = useCallback(
    (item: SelectedItem | null, node: Konva.Node | null) => {
      setSelected(item);
      const t = transformerRef.current;
      if (!t) return;
      if (item && node) {
        t.nodes([node]);
        t.getLayer()?.batchDraw();
      } else {
        t.nodes([]);
        t.getLayer()?.batchDraw();
      }
    },
    [],
  );

  const clear = useCallback(() => {
    select(null, null);
  }, [select]);

  return { selected, transformerRef, select, clear };
}

"use client";

import { useEffect, useState, type RefObject } from "react";

export interface StageSize {
  width: number;
  height: number;
}

/**
 * Observe the container element's content box and return its size in px.
 *
 * Konva.Stage needs explicit `width` + `height` props in pixels — it can't
 * track CSS sizing on its own. This hook bridges that gap via ResizeObserver.
 */
export function useKonvaStageSize(
  ref: RefObject<HTMLElement | null>,
): StageSize {
  const [size, setSize] = useState<StageSize>({ width: 0, height: 0 });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    // Seed from the initial bounding rect so first paint isn't 0×0.
    const rect = el.getBoundingClientRect();
    setSize({ width: Math.round(rect.width), height: Math.round(rect.height) });

    if (typeof ResizeObserver === "undefined") return;

    const observer = new ResizeObserver((entries) => {
      const entry = entries[0];
      if (!entry) return;
      // Prefer contentBoxSize when available (Safari 13.4+, Chrome 84+).
      const box = Array.isArray(entry.contentBoxSize)
        ? entry.contentBoxSize[0]
        : entry.contentBoxSize;
      const width = box
        ? box.inlineSize
        : entry.contentRect.width;
      const height = box
        ? box.blockSize
        : entry.contentRect.height;
      setSize({ width: Math.round(width), height: Math.round(height) });
    });
    observer.observe(el);
    return () => observer.disconnect();
  }, [ref]);

  return size;
}

"use client";

import {
  useCallback,
  useEffect,
  useRef,
  useState,
  type RefObject,
} from "react";
import {
  containerFor,
  selectRecorderMime,
} from "../lib/mime-fallback";
import type { ValidationError } from "../types";

export type CaptureStatus =
  | "idle"
  | "acquiring"
  | "ready"
  | "denied"
  | "no-camera"
  | "error";

export type FacingMode = "user" | "environment";

export interface CapturedPhoto {
  blob: Blob;
  width: number;
  height: number;
  mimeType: string;
}

export interface CapturedVideo {
  blob: Blob;
  durationMs: number;
  mimeType: string;
}

export interface UseMediaCaptureOptions {
  /** Enabled while the composer is open; releasing flips back to "idle". */
  enabled: boolean;
  /** Initial camera facing. Auto-detected from UA touch capability if undefined. */
  defaultFacing?: FacingMode;
  /**
   * Request an audio track alongside the video. Default false.
   *
   * **Critical:** only set true when the consumer actually needs audio
   * (i.e. video-mode recording). Photo / text capture should always pass
   * false — requesting mic permission for photo capture is the leading
   * cause of the v0.1.3 flicker-loop: if the user grants camera but
   * denies mic, getUserMedia({audio:true}) rejects, status becomes
   * "denied", the auto-retry effect re-fires, repeat.
   */
  requestAudio?: boolean;
  /** Hard cap on a single recording in seconds. Default 30. */
  maxVideoDurationSec?: number;
  /**
   * When true (default), automatically call `acquire()` on mount and when
   * `enabled` flips on. Set to false to require an explicit user gesture
   * (e.g. a "Tap to enable camera" button) before the camera starts —
   * recommended when the user hasn't previously granted permission, since
   * browser permission prompts are jarring without a triggering interaction.
   */
  autoAcquire?: boolean;
}

export interface UseMediaCaptureResult {
  videoRef: RefObject<HTMLVideoElement | null>;
  status: CaptureStatus;
  facing: FacingMode;
  error: Error | null;
  /** True when ≥2 video input devices are enumerated (controls switch-camera visibility). */
  canSwitchCamera: boolean;
  /** Currently active MediaStream (null until "ready"). Used by MediaRecorder. */
  stream: MediaStream | null;
  /** Re-acquire the camera (after permission grant or facing change). */
  acquire: () => Promise<void>;
  /** Stop tracks + release the stream. */
  release: () => void;
  /**
   * Snap a still frame from the current video preview.
   *
   * When `aspectRatio` is provided, the captured frame is center-cropped to
   * match — mirroring the CSS `object-cover` crop the user saw in the
   * preview. Pass the dialog/viewport aspect (e.g. `9/16`) to keep
   * what-you-see-is-what-you-get parity; pass `null`/omit to capture the
   * full native frame.
   */
  takePhoto: (opts?: { aspectRatio?: number | null }) => Promise<CapturedPhoto>;
  /** Flip facingMode and re-acquire. */
  switchCamera: () => Promise<void>;
  // ─── Video recording ──────────────────────────────────────────────────
  isRecording: boolean;
  /** Elapsed recording time in ms (updates ~10×/s). */
  recordingMs: number;
  /** Selected MIME type — null if MediaRecorder is unsupported. */
  recorderMime: string | null;
  /** Begin recording. Throws if no stream or no supported codec. */
  startRecording: () => Promise<void>;
  /** Stop recording and return the assembled blob + duration. */
  stopRecording: () => Promise<CapturedVideo>;
}

function isTouchUA(): boolean {
  if (typeof window === "undefined") return false;
  return (
    "ontouchstart" in window ||
    (navigator.maxTouchPoints ?? 0) > 0 ||
    /Android|iPhone|iPad|Mobile/i.test(navigator.userAgent)
  );
}

/**
 * getUserMedia + photo-capture lifecycle.
 *
 * C4 surface: acquire / release / takePhoto / switchCamera.
 * C5 will extend with startRecording / stopRecording.
 */
export function useMediaCapture(
  options: UseMediaCaptureOptions,
): UseMediaCaptureResult {
  const {
    enabled,
    defaultFacing,
    requestAudio = false,
    maxVideoDurationSec = 30,
    autoAcquire = true,
  } = options;
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const [stream, setStream] = useState<MediaStream | null>(null);
  const [status, setStatus] = useState<CaptureStatus>("idle");
  const [error, setError] = useState<Error | null>(null);
  const [facing, setFacing] = useState<FacingMode>(
    defaultFacing ?? (isTouchUA() ? "environment" : "user"),
  );
  const [canSwitchCamera, setCanSwitchCamera] = useState(false);

  // ─── Recording state ────────────────────────────────────────────────
  const recorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const recordStartedAtRef = useRef<number>(0);
  const tickIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const autoStopTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const stopResolverRef = useRef<{
    resolve: (v: CapturedVideo) => void;
    reject: (e: Error) => void;
  } | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingMs, setRecordingMs] = useState(0);
  const recorderMime = useRef<string | null>(null);
  // Initialize on first client render
  if (recorderMime.current === null && typeof window !== "undefined") {
    recorderMime.current = selectRecorderMime();
  }

  const release = useCallback(() => {
    const s = streamRef.current;
    if (s) {
      for (const track of s.getTracks()) track.stop();
      streamRef.current = null;
    }
    setStream(null);
    setStatus("idle");
  }, []);

  const acquire = useCallback(async () => {
    if (typeof navigator === "undefined" || !navigator.mediaDevices?.getUserMedia) {
      setStatus("no-camera");
      setError(new Error("MediaDevices.getUserMedia is not supported"));
      return;
    }
    setStatus("acquiring");
    setError(null);
    // Release any prior stream before re-acquiring (switch-camera flow).
    release();
    try {
      const next = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: { ideal: facing } },
        audio: requestAudio,
      });
      streamRef.current = next;
      setStream(next);
      setStatus("ready");

      // Enumerate devices to decide if switch-camera should be offered.
      try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        setCanSwitchCamera(
          devices.filter((d) => d.kind === "videoinput").length >= 2,
        );
      } catch {
        setCanSwitchCamera(false);
      }
    } catch (err) {
      const e = err as DOMException;
      if (e?.name === "NotAllowedError" || e?.name === "SecurityError") {
        setStatus("denied");
      } else if (e?.name === "NotFoundError") {
        setStatus("no-camera");
      } else {
        setStatus("error");
      }
      setError(err as Error);
    }
  }, [facing, requestAudio, release]);

  // Auto-acquire on mount when enabled AND autoAcquire is allowed; release
  // on unmount / disable. When autoAcquire is false the consumer is expected
  // to call `acquire()` in response to an explicit user gesture (avoids
  // jarring permission prompts on first paint).
  useEffect(() => {
    if (!enabled) {
      release();
      return;
    }
    if (autoAcquire) void acquire();
    return release;
    // We don't add `acquire` to deps directly because it changes when facing
    // flips (handled by switchCamera). But we DO depend on `requestAudio` so
    // toggling photo↔video correctly releases + re-acquires with/without an
    // audio track (without it, video mode would inherit a video-only stream
    // from a prior photo-mode acquire and record silent video).
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [enabled, requestAudio, release, autoAcquire]);

  // Attach the stream to <video>. The <video> tag will be null on first render
  // (rendered in composer-camera), so this fires whenever stream becomes ready.
  useEffect(() => {
    const v = videoRef.current;
    if (!v) return;
    if (stream) {
      v.srcObject = stream;
      v.play().catch(() => {
        /* autoplay may be blocked; ignore — user gesture will unblock */
      });
    } else {
      v.srcObject = null;
    }
  }, [stream]);

  const switchCamera = useCallback(async () => {
    const next: FacingMode = facing === "user" ? "environment" : "user";
    setFacing(next);
    // acquire() will re-fire via the effect above? No — facing change updates
    // state but the enabled-only effect won't re-run. So we call directly.
    // But acquire reads from `facing` via closure — by the time React commits
    // the new facing, our closure is stale. Use functional update + manual re-call.
    // Simpler: stop now, then defer to a microtask so React commits state, then re-acquire.
    release();
    // The effect that depends on `acquire`/`facing` won't help; do it explicitly.
    queueMicrotask(() => {
      // facing is now next via setState — but acquire's closure binds old facing.
      // To stay correct, re-derive the constraint here rather than calling acquire().
      void (async () => {
        try {
          setStatus("acquiring");
          const s = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: { ideal: next } },
            audio: requestAudio,
          });
          streamRef.current = s;
          setStream(s);
          setStatus("ready");
        } catch (err) {
          const e = err as DOMException;
          setStatus(
            e?.name === "NotAllowedError" || e?.name === "SecurityError"
              ? "denied"
              : e?.name === "NotFoundError"
                ? "no-camera"
                : "error",
          );
          setError(err as Error);
        }
      })();
    });
  }, [facing, requestAudio, release]);

  // ─── Recording controls ─────────────────────────────────────────────

  const clearRecordingTimers = useCallback(() => {
    if (tickIntervalRef.current) {
      clearInterval(tickIntervalRef.current);
      tickIntervalRef.current = null;
    }
    if (autoStopTimeoutRef.current) {
      clearTimeout(autoStopTimeoutRef.current);
      autoStopTimeoutRef.current = null;
    }
  }, []);

  const startRecording = useCallback(async () => {
    const s = streamRef.current;
    if (!s) throw new Error("Camera not ready");
    const mime = recorderMime.current ?? selectRecorderMime();
    recorderMime.current = mime;
    if (!mime) {
      throw new Error("This browser does not support video recording");
    }
    if (recorderRef.current) return; // already recording

    const rec = new MediaRecorder(s, { mimeType: mime });
    recorderRef.current = rec;
    chunksRef.current = [];
    rec.ondataavailable = (ev) => {
      if (ev.data && ev.data.size > 0) chunksRef.current.push(ev.data);
    };
    rec.onstop = () => {
      const durationMs = Date.now() - recordStartedAtRef.current;
      const blob = new Blob(chunksRef.current, { type: mime });
      const resolver = stopResolverRef.current;
      stopResolverRef.current = null;
      recorderRef.current = null;
      chunksRef.current = [];
      clearRecordingTimers();
      setIsRecording(false);
      setRecordingMs(0);
      resolver?.resolve({ blob, durationMs, mimeType: mime });
    };
    rec.onerror = (ev) => {
      const e =
        (ev as unknown as { error?: Error }).error ??
        new Error("MediaRecorder failed");
      const resolver = stopResolverRef.current;
      stopResolverRef.current = null;
      recorderRef.current = null;
      chunksRef.current = [];
      clearRecordingTimers();
      setIsRecording(false);
      setRecordingMs(0);
      resolver?.reject(e);
    };

    recordStartedAtRef.current = Date.now();
    setRecordingMs(0);
    setIsRecording(true);
    rec.start(250); // 250ms timeslice — smooth UI ticks

    // Tick recording time for UI
    tickIntervalRef.current = setInterval(() => {
      setRecordingMs(Date.now() - recordStartedAtRef.current);
    }, 100);

    // Hard cap auto-stop
    autoStopTimeoutRef.current = setTimeout(
      () => {
        if (recorderRef.current?.state === "recording") {
          recorderRef.current.stop();
        }
      },
      maxVideoDurationSec * 1000,
    );
  }, [clearRecordingTimers, maxVideoDurationSec]);

  const stopRecording = useCallback((): Promise<CapturedVideo> => {
    const rec = recorderRef.current;
    if (!rec || rec.state !== "recording") {
      return Promise.reject(new Error("Not recording"));
    }
    return new Promise<CapturedVideo>((resolve, reject) => {
      stopResolverRef.current = { resolve, reject };
      rec.stop();
    });
  }, []);

  // Cleanup any in-flight recording when stream is released / hook unmounts.
  useEffect(() => {
    return () => {
      const rec = recorderRef.current;
      if (rec && rec.state !== "inactive") {
        try {
          rec.stop();
        } catch {
          /* ignore */
        }
      }
      recorderRef.current = null;
      chunksRef.current = [];
      clearRecordingTimers();
    };
  }, [clearRecordingTimers]);

  const takePhoto = useCallback(
    async (opts?: { aspectRatio?: number | null }): Promise<CapturedPhoto> => {
      const v = videoRef.current;
      if (!v || !streamRef.current) {
        throw new Error("Camera not ready");
      }
      const nativeW = v.videoWidth;
      const nativeH = v.videoHeight;
      if (nativeW === 0 || nativeH === 0) {
        throw new Error("Video has no frame yet");
      }

      // Determine the source-rect to capture. With aspectRatio provided, we
      // center-crop the native frame to match — mirroring CSS object-cover:
      // scale-to-fill + center-crop. videoAspect > target → crop horizontal;
      // videoAspect < target → crop vertical; equal → no crop.
      const target =
        opts?.aspectRatio && opts.aspectRatio > 0 ? opts.aspectRatio : null;
      let sx = 0;
      let sy = 0;
      let sw = nativeW;
      let sh = nativeH;
      if (target !== null) {
        const videoAspect = nativeW / nativeH;
        if (videoAspect > target) {
          // Video is wider than target — crop horizontal sides.
          sw = nativeH * target;
          sx = (nativeW - sw) / 2;
        } else if (videoAspect < target) {
          // Video is taller than target — crop top/bottom.
          sh = nativeW / target;
          sy = (nativeH - sh) / 2;
        }
      }

      const outW = Math.round(sw);
      const outH = Math.round(sh);
      const canvas = document.createElement("canvas");
      canvas.width = outW;
      canvas.height = outH;
      const ctx = canvas.getContext("2d");
      if (!ctx) throw new Error("2D canvas context unavailable");
      ctx.drawImage(v, sx, sy, sw, sh, 0, 0, outW, outH);
      const blob: Blob = await new Promise((resolve, reject) => {
        canvas.toBlob(
          (b) => (b ? resolve(b) : reject(new Error("toBlob returned null"))),
          "image/jpeg",
          0.92,
        );
      });
      return { blob, width: outW, height: outH, mimeType: "image/jpeg" };
    },
    [],
  );

  return {
    videoRef,
    status,
    facing,
    error,
    canSwitchCamera,
    stream,
    acquire,
    release,
    takePhoto,
    switchCamera,
    isRecording,
    recordingMs,
    recorderMime: recorderMime.current,
    startRecording,
    stopRecording,
  };
}

/** Suggested filename for a recorded clip — useful for the publish step. */
export function suggestedVideoFilename(mime: string): string {
  return `story-${Date.now()}.${containerFor(mime) === "unknown" ? "bin" : containerFor(mime)}`;
}

// ─── Validation helpers (used by gallery picker) ────────────────────────

export function validateGalleryFile(
  file: File,
  maxFileSizeMb: number,
): ValidationError | null {
  if (!file.type.startsWith("image/") && !file.type.startsWith("video/")) {
    return {
      kind: "unsupported-type",
      message: `Unsupported file type: ${file.type || "unknown"}`,
      file,
    };
  }
  const bytes = file.size;
  const maxBytes = maxFileSizeMb * 1024 * 1024;
  if (bytes > maxBytes) {
    return {
      kind: "file-too-large",
      message: `File is ${(bytes / 1024 / 1024).toFixed(1)} MB — maximum is ${maxFileSizeMb} MB`,
      file,
    };
  }
  return null;
}

"use client";

import { useCallback, useEffect, useReducer, useRef, useState } from "react";
import type {
  AspectRatio,
  ComposerMode,
  ComposerStage,
  CropRect,
  DraftMedia,
  DrawingToolConfig,
  EditTool,
  ImageAdjustments,
  MediaEditorState,
  PlacedSticker,
  TextOnlyState,
  TextOverlay,
  TrimRange,
} from "../types";
import { DEFAULT_ADJUSTMENTS } from "../types";
import { DEFAULT_FONTS } from "../lib/defaults";
import { DEFAULT_TEXT_GRADIENTS } from "../lib/defaults";

/**
 * Editor-shaped state machine for media-editor-01.
 *
 * Pure editor concerns only — no publish/upload state (those are consumer-owned,
 * see plan §"What media-editor-01 does NOT own"). story-composer-01 v0.2.0's
 * useStoryComposerState COMPOSES this hook and augments with publish state.
 *
 * Two state surfaces are managed here:
 *   - **`state` (MediaEditorState)** — the serializable snapshot returned by
 *     `getState()` for draft persistence. Holds mode / stage / mediaSrc /
 *     overlays / filter / adjustments / crop.
 *   - **Edit working state** (alongside `state`) — captured draft, video
 *     trim, selection ids, drawing tool config, text-only state, crop
 *     aspect. These shape ongoing edits but aren't part of the persistent
 *     snapshot.
 *
 * The split keeps the persistent snapshot clean (12 fields, all content)
 * while letting the working state grow without breaking `loadState`
 * call sites.
 */

// ─── Action surface (internal) ──────────────────────────────────────────

type Action =
  | { type: "set-mode"; mode: ComposerMode | null }
  | { type: "set-stage"; stage: ComposerStage }
  | { type: "set-image-src"; src: string | null }
  | { type: "set-video-blob"; blob: Blob | null }
  | { type: "set-text-content"; content: string | null }
  | { type: "add-text-overlay"; overlay: TextOverlay }
  | { type: "update-text-overlay"; id: string; patch: Partial<TextOverlay> }
  | { type: "remove-text-overlay"; id: string }
  | { type: "add-sticker"; placed: PlacedSticker }
  | { type: "update-sticker"; id: string; patch: Partial<PlacedSticker> }
  | { type: "remove-sticker"; id: string }
  | { type: "add-drawing-stroke"; stroke: import("../types").DrawingStroke }
  | { type: "set-filter"; name: string | null }
  | { type: "set-adjustments"; adjustments: Partial<ImageAdjustments> }
  | { type: "set-crop"; crop: CropRect | null }
  | { type: "clear-layer"; layer: "drawing" | "stickers" | "text" }
  | { type: "load-state"; state: MediaEditorState }
  | { type: "reset" };

// ─── Initial state ──────────────────────────────────────────────────────

const INITIAL_STATE: MediaEditorState = {
  mode: null,
  stage: "capture",
  imageSrc: null,
  videoBlob: null,
  textBackground: null,
  textContent: null,
  textOverlays: [],
  stickers: [],
  drawingStrokes: [],
  filter: null,
  adjustments: { ...DEFAULT_ADJUSTMENTS },
  crop: null,
};

const INITIAL_DRAWING_TOOL: DrawingToolConfig = {
  color: "#ffffff",
  brushSize: 8,
  mode: "draw",
};

const INITIAL_TEXT_ONLY: TextOnlyState = {
  text: "",
  fontFamily: DEFAULT_FONTS[0]?.family ?? "Onest",
  textColor: "#ffffff",
  gradientId: DEFAULT_TEXT_GRADIENTS[0]?.id ?? "midnight",
};

// ─── Reducer ────────────────────────────────────────────────────────────

function reducer(state: MediaEditorState, action: Action): MediaEditorState {
  switch (action.type) {
    case "set-mode":
      return { ...state, mode: action.mode };
    case "set-stage":
      return { ...state, stage: action.stage };
    case "set-image-src":
      return { ...state, imageSrc: action.src };
    case "set-video-blob":
      return { ...state, videoBlob: action.blob };
    case "set-text-content":
      return { ...state, textContent: action.content };
    case "add-text-overlay":
      return { ...state, textOverlays: [...state.textOverlays, action.overlay] };
    case "update-text-overlay":
      return {
        ...state,
        textOverlays: state.textOverlays.map((o) =>
          o.id === action.id ? { ...o, ...action.patch } : o,
        ),
      };
    case "remove-text-overlay":
      return {
        ...state,
        textOverlays: state.textOverlays.filter((o) => o.id !== action.id),
      };
    case "add-sticker":
      return { ...state, stickers: [...state.stickers, action.placed] };
    case "update-sticker":
      return {
        ...state,
        stickers: state.stickers.map((s) =>
          s.id === action.id ? { ...s, ...action.patch } : s,
        ),
      };
    case "remove-sticker":
      return {
        ...state,
        stickers: state.stickers.filter((s) => s.id !== action.id),
      };
    case "add-drawing-stroke":
      return {
        ...state,
        drawingStrokes: [...state.drawingStrokes, action.stroke],
      };
    case "set-filter":
      return { ...state, filter: action.name };
    case "set-adjustments":
      return {
        ...state,
        adjustments: { ...state.adjustments, ...action.adjustments },
      };
    case "set-crop":
      return { ...state, crop: action.crop };
    case "clear-layer":
      if (action.layer === "drawing") {
        return { ...state, drawingStrokes: [] };
      }
      if (action.layer === "stickers") {
        return { ...state, stickers: [] };
      }
      return { ...state, textOverlays: [], textContent: null };
    case "load-state":
      return action.state;
    case "reset":
      return INITIAL_STATE;
    default:
      return state;
  }
}

// ─── Public hook ────────────────────────────────────────────────────────

export interface UseMediaEditorStateOptions {
  defaultMode?: ComposerMode;
  defaultCropAspect?: AspectRatio;
  onDirtyChange?: (isDirty: boolean) => void;
}

export interface UseMediaEditorStateResult {
  // === Persistent snapshot ===
  state: MediaEditorState;
  isDirty: boolean;

  // === Working / UI state (not in MediaEditorState snapshot) ===
  activeTool: EditTool | null;
  draft: DraftMedia | null;
  trim: TrimRange | null;
  selectedTextId: string | null;
  selectedStickerId: string | null;
  drawingTool: DrawingToolConfig;
  cropAspect: AspectRatio;
  textOnly: TextOnlyState;

  // === Persistent-snapshot actions ===
  setMode: (mode: ComposerMode | null) => void;
  setStage: (stage: ComposerStage) => void;
  setImageSrc: (src: string | null) => void;
  setVideoBlob: (blob: Blob | null) => void;
  setTextContent: (content: string | null) => void;
  addTextOverlay: (overlay: TextOverlay) => void;
  updateTextOverlay: (id: string, patch: Partial<TextOverlay>) => void;
  removeTextOverlay: (id: string) => void;
  addSticker: (placed: PlacedSticker) => void;
  updateSticker: (id: string, patch: Partial<PlacedSticker>) => void;
  removeSticker: (id: string) => void;
  addDrawingStroke: (stroke: import("../types").DrawingStroke) => void;
  setFilter: (name: string | null) => void;
  setAdjustments: (adjustments: Partial<ImageAdjustments>) => void;
  setCrop: (crop: CropRect | null) => void;
  clearLayer: (layer: "drawing" | "stickers" | "text") => void;
  loadState: (state: MediaEditorState) => void;
  reset: () => void;

  // === Working-state actions ===
  setActiveTool: (tool: EditTool | null) => void;
  setDraft: (draft: DraftMedia | null) => void;
  setTrim: (trim: TrimRange | null) => void;
  setSelectedTextId: (id: string | null) => void;
  setSelectedStickerId: (id: string | null) => void;
  setDrawingTool: (patch: Partial<DrawingToolConfig>) => void;
  setCropAspect: (aspect: AspectRatio) => void;
  setTextOnly: (patch: Partial<TextOnlyState>) => void;
}

export function useMediaEditorState(
  opts: UseMediaEditorStateOptions = {},
): UseMediaEditorStateResult {
  const [state, dispatch] = useReducer(reducer, INITIAL_STATE, (init) => ({
    ...init,
    mode: opts.defaultMode ?? null,
  }));

  // Working state — not part of the persistent snapshot.
  const [activeTool, setActiveToolState] = useState<EditTool | null>(null);
  const [draft, setDraftState] = useState<DraftMedia | null>(null);
  const [trim, setTrimState] = useState<TrimRange | null>(null);
  const [selectedTextId, setSelectedTextIdState] = useState<string | null>(
    null,
  );
  const [selectedStickerId, setSelectedStickerIdState] = useState<
    string | null
  >(null);
  const [drawingTool, setDrawingToolState] = useState<DrawingToolConfig>(
    INITIAL_DRAWING_TOOL,
  );
  const [cropAspect, setCropAspectState] = useState<AspectRatio>(
    opts.defaultCropAspect ?? "9:16",
  );
  const [textOnly, setTextOnlyState] = useState<TextOnlyState>(INITIAL_TEXT_ONLY);

  // Revoke draft object URL on replacement / unmount.
  const draftUrlRef = useRef<string | null>(null);
  const setDraft = useCallback((next: DraftMedia | null) => {
    setDraftState((prev) => {
      if (prev?.url && prev.url !== next?.url) {
        URL.revokeObjectURL(prev.url);
      }
      draftUrlRef.current = next?.url ?? null;
      return next;
    });
  }, []);
  useEffect(() => {
    return () => {
      if (draftUrlRef.current) URL.revokeObjectURL(draftUrlRef.current);
    };
  }, []);

  const setActiveTool = useCallback((tool: EditTool | null) => {
    setActiveToolState(tool);
  }, []);
  const setTrim = useCallback((next: TrimRange | null) => {
    setTrimState(next);
  }, []);
  const setSelectedTextId = useCallback((id: string | null) => {
    setSelectedTextIdState(id);
  }, []);
  const setSelectedStickerId = useCallback((id: string | null) => {
    setSelectedStickerIdState(id);
  }, []);
  const setDrawingTool = useCallback((patch: Partial<DrawingToolConfig>) => {
    setDrawingToolState((prev) => ({ ...prev, ...patch }));
  }, []);
  const setCropAspect = useCallback((aspect: AspectRatio) => {
    setCropAspectState(aspect);
  }, []);
  const setTextOnly = useCallback((patch: Partial<TextOnlyState>) => {
    setTextOnlyState((prev) => ({ ...prev, ...patch }));
  }, []);

  // Dirty derivation: any non-initial state counts as dirty. Includes draft
  // (capture-without-edit IS dirty per description §7) and text-only edits.
  const isDirty =
    state.mode !== null ||
    state.imageSrc !== null ||
    state.videoBlob !== null ||
    state.textContent !== null ||
    state.textOverlays.length > 0 ||
    state.stickers.length > 0 ||
    state.drawingStrokes.length > 0 ||
    state.filter !== null ||
    state.crop !== null ||
    draft !== null ||
    textOnly.text.length > 0;

  // Fire onDirtyChange when isDirty flips. Effect skips the initial mount.
  const prevDirtyRef = useRef<boolean | null>(null);
  const onDirtyChangeRef = useRef(opts.onDirtyChange);
  useEffect(() => {
    onDirtyChangeRef.current = opts.onDirtyChange;
  });
  useEffect(() => {
    if (prevDirtyRef.current !== null && prevDirtyRef.current !== isDirty) {
      onDirtyChangeRef.current?.(isDirty);
    }
    prevDirtyRef.current = isDirty;
  }, [isDirty]);

  // Reset clears BOTH the persistent snapshot AND the working state.
  const reset = useCallback(() => {
    dispatch({ type: "reset" });
    setDraft(null);
    setTrimState(null);
    setActiveToolState(null);
    setSelectedTextIdState(null);
    setSelectedStickerIdState(null);
    setTextOnlyState(INITIAL_TEXT_ONLY);
    setDrawingToolState(INITIAL_DRAWING_TOOL);
  }, [setDraft]);

  return {
    state,
    isDirty,
    activeTool,
    draft,
    trim,
    selectedTextId,
    selectedStickerId,
    drawingTool,
    cropAspect,
    textOnly,

    setMode: (mode) => dispatch({ type: "set-mode", mode }),
    setStage: (stage) => dispatch({ type: "set-stage", stage }),
    setImageSrc: (src) => dispatch({ type: "set-image-src", src }),
    setVideoBlob: (blob) => dispatch({ type: "set-video-blob", blob }),
    setTextContent: (content) =>
      dispatch({ type: "set-text-content", content }),
    addTextOverlay: (overlay) =>
      dispatch({ type: "add-text-overlay", overlay }),
    updateTextOverlay: (id, patch) =>
      dispatch({ type: "update-text-overlay", id, patch }),
    removeTextOverlay: (id) =>
      dispatch({ type: "remove-text-overlay", id }),
    addSticker: (placed) => dispatch({ type: "add-sticker", placed }),
    updateSticker: (id, patch) =>
      dispatch({ type: "update-sticker", id, patch }),
    removeSticker: (id) => dispatch({ type: "remove-sticker", id }),
    addDrawingStroke: (stroke) =>
      dispatch({ type: "add-drawing-stroke", stroke }),
    setFilter: (name) => dispatch({ type: "set-filter", name }),
    setAdjustments: (adjustments) =>
      dispatch({ type: "set-adjustments", adjustments }),
    setCrop: (crop) => dispatch({ type: "set-crop", crop }),
    clearLayer: (layer) => dispatch({ type: "clear-layer", layer }),
    loadState: (s) => dispatch({ type: "load-state", state: s }),
    reset,

    setActiveTool,
    setDraft,
    setTrim,
    setSelectedTextId,
    setSelectedStickerId,
    setDrawingTool,
    setCropAspect,
    setTextOnly,
  };
}

"use client";

import { useEffect } from "react";

/**
 * Multi-instance guard — fires a dev-only `console.warn` when 2+
 * capture-enabled `MediaEditor01` instances mount simultaneously
 * (Q-P5 lock = `b`).
 *
 * Rationale: each instance owns its own `Konva.Stage` — fine, no
 * conflict. But `getUserMedia` against the same physical camera with
 * multiple live streams degrades quickly (most browsers serialize
 * constraints to the first opener, perf cliffs hit fast). The dev-warn
 * catches the layout-builder footgun without blocking valid two-camera
 * UIs the consumer knows what they're doing about.
 *
 * Edit-only instances (no capture mode enabled) bypass the counter
 * unconditionally — per description §1 they have no camera contention
 * to worry about. The caller decides whether to engage the guard via
 * the `enabled` arg.
 *
 * The counter is module-scoped (not React state) so multiple instances
 * across the tree observe the same value. Reset semantics are
 * mount-increment / unmount-decrement; HMR drift is acceptable for a
 * dev-only diagnostic.
 */

let captureInstanceCount = 0;
let warnedAt = -1;

export function useMultiInstanceGuard(enabled: boolean): void {
  useEffect(() => {
    if (!enabled) return;
    if (process.env.NODE_ENV === "production") return;
    captureInstanceCount += 1;
    if (captureInstanceCount >= 2 && warnedAt !== captureInstanceCount) {
      warnedAt = captureInstanceCount;
      console.warn(
        `media-editor-01: ${captureInstanceCount} capture-enabled instances mounted simultaneously. ` +
          "Multiple live camera previews tend to degrade quickly — consider " +
          "`presentation=\"dialog\"` (one-at-a-time UX) or restricting secondary instances to edit-only " +
          "(`enabledModes` without `photo`/`video`).",
      );
    }
    return () => {
      captureInstanceCount = Math.max(0, captureInstanceCount - 1);
      if (captureInstanceCount < 2) {
        warnedAt = -1;
      }
    };
  }, [enabled]);
}

/**
 * Test-only — reset the module-scoped counter. Not exported via the
 * barrel; used by vitest if it ever lands.
 */
export function __resetMultiInstanceGuard(): void {
  captureInstanceCount = 0;
  warnedAt = -1;
}

"use client";

import {
  useCallback,
  useEffect,
  useRef,
  useState,
  type PointerEvent,
  type RefObject,
} from "react";

export interface PanZoomTransform {
  scale: number;
  x: number;
  y: number;
}

export interface UsePanZoomOptions {
  /**
   * Container element receiving the gestures. The wheel listener is attached
   * here as a NATIVE non-passive listener so `e.preventDefault()` actually
   * blocks the browser's default Ctrl+wheel page-zoom. React's `onWheel` is
   * registered as passive in modern browsers and can't preventDefault.
   */
  targetRef: RefObject<HTMLElement | null>;
  /** When false, all gestures + keys are no-ops. Default true. */
  enabled?: boolean;
  /** When true, the hook listens to window keydown (arrows / +/- / 0). Default true. */
  bindKeyboard?: boolean;
  /** Min zoom. Default 1 (full-screen fit baseline). */
  minScale?: number;
  /** Max zoom. Default 4. */
  maxScale?: number;
  /** Keyboard pan step in px. Default 32. */
  panStep?: number;
  /** Keyboard zoom step (multiplicative). Default 1.15. */
  zoomStep?: number;
  /**
   * Called on single-pointer pointer-down to decide whether this gesture should
   * drag-pan the canvas. Return false to yield the pointer to whatever is
   * underneath (e.g. a draggable text/sticker overlay). Receives only the
   * pointer's viewport coordinates — enough to hit-test — so callers needn't
   * accept a full React event. Default: always pan.
   */
  shouldStartPan?: (point: { clientX: number; clientY: number }) => boolean;
  /** Movement in px before a single-pointer drag counts as a pan (tap tolerance). Default 4. */
  panThreshold?: number;
}

export interface UsePanZoomResult {
  transform: PanZoomTransform;
  /** Whether the transform is at the identity (1× / 0,0) — drives the "reset" CTA. */
  isIdentity: boolean;
  /** Attach to a wrapper element receiving the gestures. */
  handlers: {
    onPointerDown: (e: PointerEvent) => void;
    onPointerMove: (e: PointerEvent) => void;
    onPointerUp: (e: PointerEvent) => void;
    onPointerCancel: (e: PointerEvent) => void;
  };
  reset: () => void;
  /** Programmatic zoom. `center` is in container coordinates. */
  zoomBy: (factor: number, center?: { x: number; y: number }) => void;
}

interface PointerInfo {
  id: number;
  x: number;
  y: number;
}

/**
 * Pan + pinch-zoom hook for the Konva editor.
 *
 * Touch:
 *   - 2-finger pinch → zoom anchored to the midpoint
 *   - 2-finger pan → translate by the midpoint delta
 *   - Single finger → drag-pan the canvas, UNLESS `shouldStartPan` vetoes the
 *     gesture (the consumer hit-tests so a finger landing on a draggable
 *     text/sticker overlay drags that overlay instead). A tap (movement under
 *     `panThreshold`) never pans, so selection/placement still works.
 *
 * Desktop:
 *   - Click-drag over the canvas → pan (same `shouldStartPan` gate).
 *   - Plain wheel over the canvas → zoom anchored to the cursor. The wheel
 *     listener is attached natively with `passive: false` + always
 *     preventDefaults, so the browser's Ctrl+wheel page-zoom doesn't ALSO
 *     zoom the page when the cursor is over the canvas. Trackpad pinch
 *     (which browsers report as wheel.ctrlKey=true) is covered too.
 *   - Vertical scroll over non-canvas areas works normally — the listener
 *     is scoped to the targetRef element.
 *
 * Keyboard (when bindKeyboard=true and no text input focused):
 *   - Arrow keys → pan (step = panStep)
 *   - + / =  → zoom in
 *   - - / _  → zoom out
 *   - 0      → reset
 *
 * Transform is returned for the consumer to apply (e.g. as Konva.Stage
 * scale + position props).
 */
export function usePanZoom(
  options: UsePanZoomOptions,
): UsePanZoomResult {
  const {
    targetRef,
    enabled = true,
    bindKeyboard = true,
    minScale = 1,
    maxScale = 4,
    panStep = 32,
    zoomStep = 1.15,
    shouldStartPan,
    panThreshold = 4,
  } = options;

  const [transform, setTransform] = useState<PanZoomTransform>({
    scale: 1,
    x: 0,
    y: 0,
  });
  const pointersRef = useRef<PointerInfo[]>([]);
  const pinchStartRef = useRef<{
    dist: number;
    midX: number;
    midY: number;
    transform: PanZoomTransform;
  } | null>(null);
  // Single-pointer drag-pan bookkeeping. `active` flips once movement crosses
  // panThreshold (so a tap stays a tap); `allowed` is the shouldStartPan verdict.
  const panStateRef = useRef<{
    id: number;
    lastX: number;
    lastY: number;
    startX: number;
    startY: number;
    active: boolean;
    allowed: boolean;
  } | null>(null);

  const clamp = useCallback(
    (s: number) => Math.max(minScale, Math.min(maxScale, s)),
    [minScale, maxScale],
  );

  const reset = useCallback(() => {
    setTransform({ scale: 1, x: 0, y: 0 });
  }, []);

  // Zoom by `factor` around `center` (in container coordinates).
  const zoomBy = useCallback(
    (factor: number, center?: { x: number; y: number }) => {
      setTransform((prev) => {
        const nextScale = clamp(prev.scale * factor);
        if (nextScale === prev.scale) return prev;
        const cx = center?.x ?? 0;
        const cy = center?.y ?? 0;
        // Keep the world point under the cursor stationary:
        //   world = (screen - pos) / scale
        //   newPos = screen - world * newScale
        const worldX = (cx - prev.x) / prev.scale;
        const worldY = (cy - prev.y) / prev.scale;
        return {
          scale: nextScale,
          x: cx - worldX * nextScale,
          y: cy - worldY * nextScale,
        };
      });
    },
    [clamp],
  );

  const panBy = useCallback((dx: number, dy: number) => {
    setTransform((prev) => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
  }, []);

  // ─── Pointer / pinch gestures ────────────────────────────────────────

  const onPointerDown = useCallback(
    (e: PointerEvent) => {
      if (!enabled) return;
      pointersRef.current = [
        ...pointersRef.current.filter((p) => p.id !== e.pointerId),
        { id: e.pointerId, x: e.clientX, y: e.clientY },
      ];
      if (pointersRef.current.length === 2) {
        const [a, b] = pointersRef.current;
        const dx = b.x - a.x;
        const dy = b.y - a.y;
        pinchStartRef.current = {
          dist: Math.hypot(dx, dy),
          midX: (a.x + b.x) / 2,
          midY: (a.y + b.y) / 2,
          transform,
        };
        // A second pointer joined → pinch owns the gesture; cancel any
        // single-pointer pan in progress.
        panStateRef.current = null;
      } else if (pointersRef.current.length === 1) {
        // Arm a single-pointer drag-pan. Whether it engages is decided by
        // shouldStartPan (so overlay drags can claim the pointer) and by
        // crossing panThreshold (so taps still register as taps).
        panStateRef.current = {
          id: e.pointerId,
          lastX: e.clientX,
          lastY: e.clientY,
          startX: e.clientX,
          startY: e.clientY,
          active: false,
          allowed: shouldStartPan ? shouldStartPan(e) : true,
        };
      }
    },
    [enabled, transform, shouldStartPan],
  );

  const onPointerMove = useCallback(
    (e: PointerEvent) => {
      if (!enabled) return;
      const ptrs = pointersRef.current;
      const idx = ptrs.findIndex((p) => p.id === e.pointerId);
      if (idx === -1) return;
      ptrs[idx] = { id: e.pointerId, x: e.clientX, y: e.clientY };

      // Single-pointer drag-pan (desktop click-drag + touch one-finger).
      const ps = panStateRef.current;
      if (ptrs.length === 1 && ps && ps.id === e.pointerId && ps.allowed) {
        if (!ps.active) {
          if (
            Math.hypot(e.clientX - ps.startX, e.clientY - ps.startY) <
            panThreshold
          ) {
            return;
          }
          // Crossing the threshold: anchor the pan to HERE so the first frame
          // doesn't jump by the accumulated pre-threshold distance (up to
          // panThreshold px). Subsequent frames compute incremental deltas.
          ps.active = true;
          ps.lastX = e.clientX;
          ps.lastY = e.clientY;
          return;
        }
        const dx = e.clientX - ps.lastX;
        const dy = e.clientY - ps.lastY;
        ps.lastX = e.clientX;
        ps.lastY = e.clientY;
        panBy(dx, dy);
        return;
      }

      if (ptrs.length === 2 && pinchStartRef.current) {
        const [a, b] = ptrs;
        const dx = b.x - a.x;
        const dy = b.y - a.y;
        const dist = Math.hypot(dx, dy);
        const midX = (a.x + b.x) / 2;
        const midY = (a.y + b.y) / 2;
        const start = pinchStartRef.current;

        const rawScale = (start.transform.scale * dist) / start.dist;
        const nextScale = clamp(rawScale);

        // Anchor the start midpoint's world coords under the current midpoint.
        const worldX = (start.midX - start.transform.x) / start.transform.scale;
        const worldY = (start.midY - start.transform.y) / start.transform.scale;
        setTransform({
          scale: nextScale,
          x: midX - worldX * nextScale,
          y: midY - worldY * nextScale,
        });
      }
    },
    [clamp, enabled, panBy, panThreshold],
  );

  const onPointerUp = useCallback((e: PointerEvent) => {
    pointersRef.current = pointersRef.current.filter(
      (p) => p.id !== e.pointerId,
    );
    if (pointersRef.current.length < 2) pinchStartRef.current = null;
    if (panStateRef.current?.id === e.pointerId) panStateRef.current = null;
  }, []);

  const onPointerCancel = onPointerUp;

  // ─── Wheel (native non-passive — beats browser page-zoom) ────────────
  // Plain wheel (no modifier) zooms when over the canvas. Always
  // preventDefaults so the browser doesn't also zoom the page.

  useEffect(() => {
    if (!enabled) return;
    const el = targetRef.current;
    if (!el) return;
    const handler = (e: WheelEvent) => {
      e.preventDefault();
      const rect = el.getBoundingClientRect();
      const center = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      };
      const factor = e.deltaY < 0 ? zoomStep : 1 / zoomStep;
      zoomBy(factor, center);
    };
    el.addEventListener("wheel", handler, { passive: false });
    return () => el.removeEventListener("wheel", handler);
  }, [enabled, targetRef, zoomBy, zoomStep]);

  // ─── Keyboard ────────────────────────────────────────────────────────

  useEffect(() => {
    if (!enabled || !bindKeyboard || typeof window === "undefined") return;
    const handler = (e: KeyboardEvent) => {
      // Don't hijack while typing.
      const tgt = e.target as HTMLElement | null;
      if (
        tgt?.tagName === "INPUT" ||
        tgt?.tagName === "TEXTAREA" ||
        tgt?.isContentEditable
      ) {
        return;
      }
      // Arrow keys move the IMAGE in the arrow's direction (the natural
      // mental model when you're looking at media you want to reposition),
      // not the viewport. ArrowRight ⇒ image shifts right ⇒ transform.x +.
      switch (e.key) {
        case "ArrowLeft":
          panBy(-panStep, 0);
          e.preventDefault();
          break;
        case "ArrowRight":
          panBy(panStep, 0);
          e.preventDefault();
          break;
        case "ArrowUp":
          panBy(0, -panStep);
          e.preventDefault();
          break;
        case "ArrowDown":
          panBy(0, panStep);
          e.preventDefault();
          break;
        case "+":
        case "=":
          zoomBy(zoomStep);
          e.preventDefault();
          break;
        case "-":
        case "_":
          zoomBy(1 / zoomStep);
          e.preventDefault();
          break;
        case "0":
          reset();
          e.preventDefault();
          break;
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [bindKeyboard, enabled, panBy, panStep, reset, zoomBy, zoomStep]);

  return {
    transform,
    isIdentity:
      transform.scale === 1 && transform.x === 0 && transform.y === 0,
    handlers: {
      onPointerDown,
      onPointerMove,
      onPointerUp,
      onPointerCancel,
    },
    reset,
    zoomBy,
  };
}

import type { StickerOption, StickerSet } from "../types";

/**
 * Built-in emoji stickers (Q-P9a — inline data URLs in TS).
 *
 * Implemented as SVG-text data URLs rather than base64 PNGs:
 *   - Each sticker is ~180 bytes vs ~3-5KB for an equivalent PNG.
 *   - Vector — scales infinitely with Transformer.
 *   - Renders consistently regardless of host emoji-font (the SVG inlines
 *     the unicode codepoint and the browser renders with its system emoji).
 *
 * Total payload for the 36 stickers below: ~6KB → no measurable bundle
 * bloat (well under the ~80KB ceiling that would trigger a switch to
 * the separate-PNG-files pattern from description §15 Q-P9b).
 */

function emojiSticker(id: string, emoji: string, alt: string): StickerOption {
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 256 256"><text x="128" y="170" font-size="200" text-anchor="middle">${emoji}</text></svg>`;
  return {
    id,
    src: `data:image/svg+xml;utf8,${encodeURIComponent(svg)}`,
    alt,
    width: 256,
    height: 256,
  };
}

