import type { AspectRatio } from "../types";

export interface DialogDims {
  /** CSS `aspect-ratio` value, e.g. `"9 / 16"`. */
  aspectRatio: string;
  /** Drives which dimension is the viewport-relative driver. */
  orientation: "portrait" | "landscape";
}

/**
 * Aspect → desktop dialog sizing hints per description §6.
 *
 * Mobile (< md breakpoint) always falls back to fullscreen; these hints only
 * take effect at the `md:` breakpoint, where the dialog is constructed as a
 * viewport-relative box constrained by `aspect-ratio` — height-driven for
 * portrait aspects, width-driven for landscape. The CSS in media-editor-01.tsx
 * sets the driver dimension to a viewport-relative size (e.g. `85dvh`) and
 * lets `aspect-ratio` compute the other.
 *
 * v0.1 does NOT expose a width-override prop — consumers needing custom sizing
 * pass `presentation="inline"` and own the wrapper.
 */
const DIALOG_DIMS_FOR_ASPECT: Record<AspectRatio, DialogDims> = {
  "9:16": { aspectRatio: "9 / 16", orientation: "portrait" },
  "1:1": { aspectRatio: "1 / 1", orientation: "portrait" },
  "16:9": { aspectRatio: "16 / 9", orientation: "landscape" },
  "4:5": { aspectRatio: "4 / 5", orientation: "portrait" },
  free: { aspectRatio: "4 / 3", orientation: "landscape" },
};

export function dialogDimsForAspect(aspect: AspectRatio): DialogDims {
  return DIALOG_DIMS_FOR_ASPECT[aspect];
}

import type Konva from "konva";
import type { CropRect } from "../types";

export interface ExportPhotoOptions {
  stage: Konva.Stage;
  cropRect?: CropRect | null;
  /** Pixel ratio multiplier. Default 2 for retina sharpness. */
  pixelRatio?: number;
  /** Default "image/jpeg" per Q-P3 lock. PNG and WebP also supported. */
  mimeType?: "image/jpeg" | "image/png" | "image/webp";
  /** 0..1; default 0.9 per Q-P3. Only meaningful for jpeg / webp. */
  quality?: number;
  /** Fires (0) at start and (1) at end. Two-tick contract for image export. */
  onProgress?: (progress: number) => void;
}

/**
 * Export the Konva stage to a Blob at the crop rect (or full stage if none).
 *
 * Uses stage.toCanvas() with x/y/width/height to write only the crop region.
 * stage.toBlob() is not available in all Konva versions; the canvas →
 * toBlob() path is more portable.
 *
 * Progress emits twice for jpeg/png/webp (start=0, end=1) per the
 * ExportImageOpts.onProgress contract. WebP encoders in some browsers may
 * yield mid-encode but we don't expose those intermediate ticks.
 */
export function exportPhotoBlob(opts: ExportPhotoOptions): Promise<Blob> {
  const {
    stage,
    cropRect,
    pixelRatio = 2,
    mimeType = "image/jpeg",
    quality = 0.9,
    onProgress,
  } = opts;

  const region = cropRect ?? {
    x: 0,
    y: 0,
    width: stage.width(),
    height: stage.height(),
  };

  onProgress?.(0);

  const canvas = stage.toCanvas({
    x: region.x,
    y: region.y,
    width: region.width,
    height: region.height,
    pixelRatio,
  });

  return new Promise<Blob>((resolve, reject) => {
    canvas.toBlob(
      (b) => {
        if (b) {
          onProgress?.(1);
          resolve(b);
        } else {
          reject(new Error("Canvas.toBlob returned null"));
        }
      },
      mimeType,
      quality,
    );
  });
}

/**
 * Export a text-only mode capture from a DOM element using html-to-canvas?
 * No — text-mode renders via a styled <div> with the gradient + text. We
 * reuse the Konva editor when text-mode is captured-to-image. For now this
 * is a placeholder — text-only export lands fully in C13 alongside the
 * text-only canvas component.
 */
export async function exportTextOnlyBlob(
  source: HTMLElement,
  width: number,
  height: number,
): Promise<Blob> {
  // SVG-foreignObject technique: serialise the element into an SVG with
  // <foreignObject>, then draw the SVG onto a canvas. This avoids a
  // third-party html-to-canvas dependency.
  const xml = new XMLSerializer().serializeToString(source);
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}"><foreignObject width="100%" height="100%">${xml}</foreignObject></svg>`;
  const blob = new Blob([svg], { type: "image/svg+xml;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  try {
    const img = new Image();
    await new Promise<void>((resolve, reject) => {
      img.onload = () => resolve();
      img.onerror = () => reject(new Error("Text-mode SVG render failed"));
      img.src = url;
    });
    const canvas = document.createElement("canvas");
    canvas.width = width * 2;
    canvas.height = height * 2;
    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error("2D context unavailable");
    ctx.scale(2, 2);
    ctx.drawImage(img, 0, 0, width, height);
    return await new Promise<Blob>((resolve, reject) => {
      canvas.toBlob(
        (b) => (b ? resolve(b) : reject(new Error("toBlob null"))),
        "image/png",
      );
    });
  } finally {
    URL.revokeObjectURL(url);
  }
}

// initial-source-loader — InitialSource intake + validation (C9).
//
// Pure helpers (no React). Resolves `InitialSource` → either a loaded
// payload (object URL + derived mode + blob) or a `SourceError` per
// description §5 validation rules:
//
//   - For `kind: "file"`, mode is derived from `File.type` prefix.
//   - For `kind: "url"`, `fetch()` is attempted; CORS / network failures
//     surface as `kind: "cors"` or `kind: "fetch-failed"`.
//   - For `kind: "blob"`, mode is the consumer-supplied value.
//   - In all paths, the resolved mode MUST be a member of `enabledModes`.
//     Mismatch → `kind: "mode-not-enabled"`.
//   - Empty / blank blobs → `kind: "invalid-blob"`.
//
// The orchestrator owns objectURL lifetime — the loader returns the URL
// and the caller is expected to revoke it on unmount / source change.

import type { ComposerMode, InitialSource, SourceError } from "../types";

export type LoadedInitialSource = {
  mode: "photo" | "video";
  blob: Blob;
  objectUrl: string;
};

export type LoadInitialSourceResult =
  | { ok: true; loaded: LoadedInitialSource }
  | { ok: false; error: SourceError };

/**
 * Derive mode from a `File.type` MIME prefix. Returns `null` for anything
 * other than `image/*` or `video/*` (consumer should treat as unsupported).
 */
export function inferModeFromFile(
  file: File,
): "photo" | "video" | null {
  const type = file.type ?? "";
  if (type.startsWith("image/")) return "photo";
  if (type.startsWith("video/")) return "video";
  return null;
}

/**
 * Resolve `InitialSource` to either a loaded payload or a `SourceError`.
 *
 * The returned object URL is allocated via `URL.createObjectURL` — caller
 * MUST revoke it (typically on unmount / next source change) to avoid
 * leaking blob references.
 *
 * `enabledModes` gates the resolved mode. If the consumer disabled the
 * mode required by the source, returns `mode-not-enabled` without
 * fetching (URL path) — so we don't waste a request on a source we
 * can't display anyway.
 */
export async function loadInitialSource(
  source: InitialSource,
  enabledModes: readonly ComposerMode[],
): Promise<LoadInitialSourceResult> {
  // Step 1 — resolve { mode, blob }. file/blob paths are sync; url path fetches.
  let mode: "photo" | "video";
  let blob: Blob;

  if (source.kind === "file") {
    const inferred = inferModeFromFile(source.file);
    if (inferred === null) {
      return {
        ok: false,
        error: {
          kind: "unsupported-file-type",
          fileType: source.file.type ?? "",
          file: source.file,
        },
      };
    }
    mode = inferred;
    blob = source.file;
  } else if (source.kind === "blob") {
    mode = source.mode;
    blob = source.blob;
  } else {
    // kind === "url"
    mode = source.mode;
    // Pre-check enabledModes before paying the network cost.
    // Empty enabledModes signals the edit-only path (initialSource without
    // capture); the mode gate only applies when the consumer has explicitly
    // enabled at least one capture mode.
    if (enabledModes.length > 0 && !enabledModes.includes(mode)) {
      return {
        ok: false,
        error: {
          kind: "mode-not-enabled",
          attempted: mode,
          enabled: [...enabledModes],
        },
      };
    }
    try {
      const res = await fetch(source.url, { mode: "cors" });
      if (!res.ok) {
        return {
          ok: false,
          error: {
            kind: "fetch-failed",
            url: source.url,
            underlying: new Error(`HTTP ${res.status} ${res.statusText}`),
          },
        };
      }
      blob = await res.blob();
    } catch (err) {
      // CORS rejection surfaces as TypeError per spec; non-CORS network
      // failures usually do too. The distinction matters for the consumer's
      // recovery path (pre-fetch + blob vs. retry url), so we attempt to
      // disambiguate via the error name + message.
      const underlying = err instanceof Error ? err : new Error(String(err));
      const looksLikeCors =
        underlying.name === "TypeError" &&
        /cors|cross.origin|failed to fetch|networkerror/i.test(
          underlying.message,
        );
      return {
        ok: false,
        error: looksLikeCors
          ? { kind: "cors", url: source.url, underlying }
          : { kind: "fetch-failed", url: source.url, underlying },
      };
    }
  }

  // Step 2 — validate against enabledModes (file/blob paths only; url path
  // pre-checked above to avoid a wasted fetch). Empty enabledModes = edit-only
  // path, same exemption as the url pre-check.
  if (enabledModes.length > 0 && !enabledModes.includes(mode)) {
    return {
      ok: false,
      error: {
        kind: "mode-not-enabled",
        attempted: mode,
        enabled: [...enabledModes],
      },
    };
  }

  // Step 3 — sanity-check the blob isn't empty.
  if (blob.size === 0) {
    return {
      ok: false,
      error: {
        kind: "invalid-blob",
        reason: "Blob is empty (size: 0).",
      },
    };
  }

  // Step 4 — allocate the object URL. Caller owns revocation.
  const objectUrl = URL.createObjectURL(blob);
  return { ok: true, loaded: { mode, blob, objectUrl } };
}

