/**
 * Merge consumer-supplied presets with built-ins.
 * `replace` true → consumer set wins entirely (no built-ins).
 */
export function resolveFilterPresets(
  consumer: FilterPreset[] | undefined,
  replace: boolean,
): FilterPreset[] {
  if (replace) return consumer ?? [];
  if (!consumer || consumer.length === 0) return BUILT_IN_FILTER_PRESETS;
  // Consumer presets appended after built-ins; ids are not de-duped (consumer's
  // responsibility — id collisions can't happen by accident with built-in names).
  return [...BUILT_IN_FILTER_PRESETS, ...consumer];
}

/**
 * MediaRecorder codec preference chain.
 *
 * Chrome/Edge/Firefox prefer WebM (VP9 → VP8); Safari only supports MP4.
 * Each entry includes the audio codec so the resulting MIME string is
 * directly usable in `new MediaRecorder(stream, { mimeType })`.
 */
export const PREFERRED_RECORDER_MIME_TYPES = [
  "video/webm;codecs=vp9,opus",
  "video/webm;codecs=vp8,opus",
  "video/webm",
  "video/mp4;codecs=avc1.42E01E,mp4a.40.2",
  "video/mp4;codecs=avc1,mp4a",
  "video/mp4",
] as const;

export type RecorderMimeType = (typeof PREFERRED_RECORDER_MIME_TYPES)[number];

/**
 * Picks the highest-preference MIME the current browser supports for
 * MediaRecorder. Returns null when nothing matches (very old browsers).
 */
export function selectRecorderMime(): RecorderMimeType | null {
  if (typeof MediaRecorder === "undefined") return null;
  for (const mime of PREFERRED_RECORDER_MIME_TYPES) {
    try {
      if (MediaRecorder.isTypeSupported(mime)) return mime;
    } catch {
      // Some browsers throw on unknown MIMEs — keep looking.
    }
  }
  return null;
}

/** Extracts the bare container ("webm" or "mp4") for filename hints. */
export function containerFor(mime: string): "webm" | "mp4" | "unknown" {
  if (mime.startsWith("video/webm")) return "webm";
  if (mime.startsWith("video/mp4")) return "mp4";
  return "unknown";
}

import type { ComposerMode } from "../types";

export type ResolvedPresentation = "inline" | "dialog";

/**
 * Resolves the runtime `presentation` mode per description §6.
 *
 * Rules:
 *  - "inline" — render bare in parent layout. No portal/modal/focus-trap.
 *  - "dialog" — wrap in shadcn dialog.
 *  - "auto"   — if `enabledModes` is empty (pure-edit context, no capture
 *               surface), pick "inline". Otherwise pick "dialog". The presence
 *               of `initialSource` does NOT change the rule.
 */
export function resolvePresentation(
  presentation: "inline" | "dialog" | "auto" | undefined,
  enabledModes: readonly ComposerMode[],
): ResolvedPresentation {
  if (presentation === "inline") return "inline";
  if (presentation === "dialog") return "dialog";
  // auto (or undefined, defaults to auto)
  return enabledModes.length === 0 ? "inline" : "dialog";
}

import type { AspectRatio } from "../types";

const ALL_ASPECTS: readonly AspectRatio[] = [
  "9:16",
  "1:1",
  "16:9",
  "4:5",
  "free",
];

/**
 * Crop tool's `cropAspects` default-derivation per description §4 "crop" row:
 *
 *   - If parent `aspect !== "free"` (canvas IS locked):
 *       default cropAspects = [aspect] — crop tool offers sub-region selection
 *       WITHIN the locked aspect only.
 *
 *   - If parent `aspect === "free"` (no canvas lock):
 *       default cropAspects = ["9:16","1:1","16:9","4:5","free"] — full menu.
 *
 *   - If consumer passes `cropAspects` explicitly, that overrides the default.
 */
export function resolveCropAspects(
  aspect: AspectRatio,
  cropAspectsOverride: AspectRatio[] | undefined,
): AspectRatio[] {
  if (cropAspectsOverride !== undefined) return cropAspectsOverride;
  if (aspect === "free") return [...ALL_ASPECTS];
  return [aspect];
}

"use client";

import { Camera, AlertTriangle } from "lucide-react";
import { Button } from "@/components/ui/button";
