   * Numeric aspect-ratio (width/height) of the visible preview region. When
   * provided, the captured photo is center-cropped to match — mirroring the
   * preview's CSS `object-cover` crop. Pass `null` for free (no crop).
   */
  captureAspectRatio?: number | null;
  /**
   * When true, force auto-acquire of the camera on mount even if browser
   * permission isn't pre-granted — used after an explicit user gesture (e.g.
   * the "Connect to camera" entry button or a mode-tab click) so the
   * subsequent permission prompt fires in the same gesture-credited tick.
   * Default behavior auto-acquires only when `perms.state === "granted"`.
   */
  autoAcquireOverride?: boolean;
  labels: Required<StoryComposer01Labels>;
  onPhoto: (photo: CapturedPhoto) => void;
  onVideo: (video: CapturedVideo) => void;
  /** Loads an image / video file picked from the gallery into the editor. */
  onGalleryFile: (file: File) => void;
  onValidationError?: (error: ValidationError) => void;
  /** Fires when permission is denied so the host can show its own help. */
  onPermissionDenied?: () => void;
}

export function EditorCamera({
  enabled,
  mode,
  defaultFacing,
  recordAudio = true,
  maxFileSizeMb = 50,
  maxVideoDurationSec = 30,
  captureAspectRatio,
  autoAcquireOverride,
  labels,
  onPhoto,
  onVideo,
  onGalleryFile,
  onValidationError,
  onPermissionDenied,
}: EditorCameraProps) {
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const [busy, setBusy] = useState(false);

  const perms = useCameraPermissions();
  // Only request mic permission for video mode — requesting audio in photo
  // mode caused the v0.1.3 flicker loop (user might have mic denied while
  // camera is granted; getUserMedia rejects → status flips → auto-retry).
  const requestAudio = mode === "video" && recordAudio;
  // Auto-acquire only if the browser has already granted camera permission;
  // otherwise wait for an explicit user gesture (the "Enable camera" button
  // on the idle prompt). Avoids surprising users with a permission prompt
  // the moment they open the composer.
  const capture = useMediaCapture({
    enabled,
    defaultFacing,
    requestAudio,
    maxVideoDurationSec,
    autoAcquire: autoAcquireOverride || perms.state === "granted",
  });

  // Surface permission-denied to the consumer once.
  const deniedFiredRef = useRef(false);
  useEffect(() => {
    if (capture.status === "denied" && !deniedFiredRef.current) {
      deniedFiredRef.current = true;
      onPermissionDenied?.();
    } else if (capture.status !== "denied") {
      deniedFiredRef.current = false;
    }
  }, [capture.status, onPermissionDenied]);

  // Front-camera preview is mirrored to match user expectation; rear is not.
  const mirrored = capture.facing === "user";

  const handleShutterPhoto = async () => {
    if (busy || capture.status !== "ready") return;
    setBusy(true);
    try {
      const photo = await capture.takePhoto({
        aspectRatio: captureAspectRatio ?? null,
      });
      onPhoto(photo);
    } catch {
      /* swallow — could surface as ValidationError later */
    } finally {
      setBusy(false);
    }
  };

  const handleVideoStart = async () => {
    if (busy || capture.status !== "ready") return;
    try {
      await capture.startRecording();
    } catch (err) {
      onValidationError?.({
        kind: "unsupported-codec",
        message:
          (err as Error)?.message ?? "Video recording is not supported here",
      });
    }
  };

  const handleVideoStop = async () => {
    if (!capture.isRecording) return;
    setBusy(true);
    try {
      const video = await capture.stopRecording();
      onVideo(video);
    } catch {
      /* swallow */
    } finally {
      setBusy(false);
    }
  };

  const handleGalleryClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    e.target.value = ""; // reset so picking the same file twice re-fires
    if (!file) return;
    const err = validateGalleryFile(file, maxFileSizeMb);
    if (err) {
      onValidationError?.(err);
      return;
    }
    onGalleryFile(file);
  };

  // ─── Permission UI ────────────────────────────────────────────────────
  const permissionVariant:
    | null
    | "idle"
    | "pending"
    | "denied"
    | "no-camera"
    | "error" =
    capture.status === "acquiring"
      ? "pending"
      : capture.status === "denied"
        ? "denied"
        : capture.status === "no-camera"
          ? "no-camera"
          : capture.status === "error"
            ? "error"
            : capture.status === "idle"
              ? "idle"
              : null;

  // Auto-retry on permission change (Q-P8a) — when the watcher flips to
  // "granted" but our capture is still in "denied", silently re-acquire.
  //
  // BOUNDED — fires AT MOST ONCE per granted-state transition. Without this
  // bound, a stable denial (e.g. mic denied while photo mode requests it)
  // makes acquire() → fail → status="denied" → effect re-fires → infinite
  // loop. Resets when status becomes "ready" so a future denial can retry.
  // Also gates on .status to avoid dep'ing on the whole capture object
  // (which is a fresh ref every render).
  const autoRetryAttemptedRef = useRef(false);
  useEffect(() => {
    if (perms.state === "granted") {
      if (capture.status === "denied" && !autoRetryAttemptedRef.current) {
        autoRetryAttemptedRef.current = true;
        void capture.acquire();
      } else if (capture.status === "ready") {
        autoRetryAttemptedRef.current = false;
      }
    } else {
      autoRetryAttemptedRef.current = false;
    }
  }, [perms.state, capture.status, capture.acquire]);

  return (
    <div className="@container relative flex-1 flex flex-col overflow-hidden">
      {/* Live preview — black fallback shows when no stream */}
      <video
        ref={capture.videoRef}
        autoPlay
        playsInline
        muted
        className={cn(
          "absolute inset-0 w-full h-full object-cover bg-black",
          mirrored && "scale-x-[-1]",
          permissionVariant !== null && "opacity-0",
        )}
      />

      {/* Permission overlay (denied / pending / no-camera / error) */}
      {permissionVariant !== null && (
        <div className="absolute inset-0 flex items-center justify-center bg-black">
          <CameraPermissionPrompt
            variant={permissionVariant}
            labels={labels}
            onRetry={() => void capture.acquire()}
            onUsePicker={handleGalleryClick}
          />
        </div>
      )}

      {/* Recording indicator — red dot + mm:ss top-center */}
      {capture.isRecording && (
        <div
          role="status"
          aria-live="polite"
          className="absolute top-16 left-1/2 -translate-x-1/2 z-20 flex items-center gap-2 rounded-full bg-black/60 backdrop-blur-md px-3 py-1.5 text-white"
        >
          <span className="size-2 rounded-full bg-red-500 animate-pulse" />
          <span className="text-xs font-mono tabular-nums">
            {formatRecordingTime(capture.recordingMs)}
          </span>
          <span className="sr-only">{labels.recordingLabel}</span>
        </div>
      )}

      {/* Bottom control row — gallery / shutter / switch-camera */}
      <div
        className={cn(
          "absolute left-0 right-0 z-20 flex items-center justify-between px-6",
          "bottom-[max(1.25rem,env(safe-area-inset-bottom))]",
        )}
      >
        {/* Gallery picker */}
        <Button
          variant="ghost"
          size="icon"
          onClick={handleGalleryClick}
          aria-label={labels.galleryPicker}
          className="size-[clamp(2rem,9cqw,2.5rem)] rounded-full bg-black/40 backdrop-blur-md text-white hover:bg-black/60 hover:text-white"
        >
          <ImageIcon className="size-[55%]" />
        </Button>

        {/* Shutter — photo: tap | video: long-press hold OR tap-to-toggle */}
        <ShutterButton
          mode={mode === "video" ? "video" : "photo"}
          // Sized to the camera width (container query) — not the viewport — so
          // it stays proportional in the dialog / chat embeds instead of
          // ballooning when the browser window is wide.
          className="size-[clamp(2.75rem,15cqw,3.5rem)]"
          onPress={handleShutterPhoto}
          onStart={handleVideoStart}
          onStop={handleVideoStop}
          isRecording={capture.isRecording}
          recordProgress={
            capture.isRecording
              ? Math.min(
                  1,
                  capture.recordingMs / (maxVideoDurationSec * 1000),
                )
              : 0
          }
          disabled={
            busy ||
            capture.status !== "ready" ||
            mode === "text"
          }
          ariaLabel={
            mode === "video"
              ? capture.isRecording
                ? labels.shutterVideoStop
                : labels.shutterVideoStart
              : labels.shutterPhoto
          }
        />

        {/* Switch camera (only when ≥2 devices) */}
        {capture.canSwitchCamera ? (
          <Button
            variant="ghost"
            size="icon"
            onClick={() => void capture.switchCamera()}
            aria-label={labels.switchCamera}
            className="size-[clamp(2rem,9cqw,2.5rem)] rounded-full bg-black/40 backdrop-blur-md text-white hover:bg-black/60 hover:text-white"
          >
            <SwitchCamera className="size-[55%]" />
          </Button>
        ) : (
          <div className="size-[clamp(2rem,9cqw,2.5rem)]" aria-hidden />
        )}
      </div>

      {/* Hidden file input for gallery pick */}
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*,video/*"
        onChange={handleFileChange}
        className="hidden"
      />
    </div>
  );
}

function formatRecordingTime(ms: number): string {
  const totalSec = Math.floor(ms / 1000);
  const m = Math.floor(totalSec / 60);
  const s = totalSec % 60;
  return `${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import Konva from "konva";
import type { Filter as KonvaFilter } from "konva/lib/Node";
import {
  Stage,
  Layer,
  Image as KonvaImage,
  Line as KonvaLine,
  Text as KonvaText,
  Transformer,
} from "react-konva";
import { cn } from "@/lib/utils";
import {
  useKonvaStageSize,
  useKonvaSelection,
  usePanZoom,
  type StageSize,
} from "../../media-editor-01";
import { Button } from "@/components/ui/button";
import { Maximize2 } from "lucide-react";
import type { CropRect } from "./tool-crop-overlay";
import type {
  DrawingStroke,
  FilterPreset,
  ImageAdjustments,
  PlacedSticker,
  StickerOption,
  TextOverlay,
} from "../types";

export interface EditorCanvasProps {
  /** Image draft preview URL. For video drafts, the editor renders a <video> overlay instead (C7+). */
  imageUrl: string | null;
  /** Video draft preview URL (overlay edits land C7+; for now displays as background). */
  videoUrl?: string | null;
  /** Canvas surface background — usually composer's editorBackground. */
  background?: string;
  /** Brightness/contrast/saturation/blur sliders (C7). */
  adjustments?: ImageAdjustments;
  /** Active filter preset (C7). null = no preset. */
  activeFilter?: FilterPreset | null;
  /** Text overlays (C8). */
  textOverlays?: TextOverlay[];
  /** Currently selected text overlay id (C8). */
  selectedTextId?: string | null;
  /** Fired on drag-end or transform-end of a text overlay. */
  onTextChange?: (next: TextOverlay) => void;
  /** Fired when a text overlay is tapped (selects it). */
  onTextSelect?: (id: string | null) => void;
  /** Sticker overlays (C9). */
  stickers?: PlacedSticker[];
  /** Sticker-id → StickerOption resolver (lets the editor look up src/dimensions). */
  resolveSticker?: (stickerId: string) => StickerOption | undefined;
  /** Currently selected sticker id (C9). */
  selectedStickerId?: string | null;
  onStickerChange?: (next: PlacedSticker) => void;
  onStickerSelect?: (id: string | null) => void;
  /** Completed drawing strokes (C10). */
  drawingStrokes?: DrawingStroke[];
  /** In-progress stroke (rendered live while pointer is down). */
  currentDrawingStroke?: DrawingStroke | null;
  /** When true, Stage pointer events feed the drawing pipeline. */
  isDrawing?: boolean;
  onDrawBegin?: (x: number, y: number) => void;
  onDrawExtend?: (x: number, y: number) => void;
  onDrawEnd?: () => void;
  /** Crop rect in stage coordinates (C11). Editor renders a dim+frame overlay when active. */
  cropRect?: CropRect | null;
  /** When true, the crop overlay is interactive (drag handles + reposition). */
  cropActive?: boolean;
  /** Aspect ratio of crop — locks resize behavior. */
  cropAspectRatio?: number | null;
  onCropChange?: (next: CropRect) => void;
  /** Surfaces stage dimensions to the parent (used to recompute crop rects on aspect change). */
  onStageSize?: (size: { width: number; height: number }) => void;
  /** Surfaces the underlying Konva.Stage instance for export (C12). */
  onStageReady?: (stage: Konva.Stage | null) => void;
  className?: string;
}

/**
 * Multi-layer Konva canvas with:
 *   <Layer id="image">     — captured media as Konva.Image (filters land C7)
 *   <Layer id="drawing">   — freehand strokes (C10)
 *   <Layer id="stickers">  — sticker instances (C9)
 *   <Layer id="text">      — text overlays (C8)
 *   <Layer id="ui">        — Konva.Transformer (selection handles)
 *
 * C6: only the image layer renders. Other layers are wired empty so
 * subsequent commits land their items into the right z-order without
 * a substrate refactor.
 */
export function EditorCanvas({
  imageUrl,
  videoUrl,
  background = "#000",
  adjustments,
  activeFilter,
  textOverlays,
  selectedTextId,
  onTextChange,
  onTextSelect,
  stickers,
  resolveSticker,
  selectedStickerId,
  onStickerChange,
  onStickerSelect,
  drawingStrokes,
  currentDrawingStroke,
  isDrawing = false,
  onDrawBegin,
  onDrawExtend,
  onDrawEnd,
  cropRect,
  cropActive = false,
  cropAspectRatio,
  onCropChange,
  onStageSize,
  onStageReady,
  className,
}: EditorCanvasProps) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const stageRef = useRef<Konva.Stage | null>(null);
  const stageSize = useKonvaStageSize(containerRef);
  const selection = useKonvaSelection();
  const imageNodeRef = useRef<Konva.Image | null>(null);

  // Single-pointer drag-pan must yield to draggable overlays. Hit-test the
  // stage on pointer-down: if a listening node (text / sticker / transformer
  // handle) is under the pointer, don't pan — let Konva drag that node. The
  // image layer is listening={false}, so background/image hits return null →
  // pan engages.
  const shouldStartPan = useCallback((e: { clientX: number; clientY: number }) => {
    const stage = stageRef.current;
    if (!stage) return true;
    const rect = stage.container().getBoundingClientRect();
    return !stage.getIntersection({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    });
  }, []);

  // Pan + pinch-zoom (single-pointer drag / touch 2-finger / wheel / keyboard).
  // Disabled when:
  //   - drawing is active (Stage owns the pointer pipeline for strokes)
  //   - cropping is active (crop overlay is DOM; can't follow stage transform)
  const panZoom = usePanZoom({
    targetRef: containerRef,
    enabled: !isDrawing && !cropActive,
    shouldStartPan,
  });

  const [image, imageSize] = useImage(imageUrl);
  const fit = fitInto(imageSize, stageSize);

  // Plain-<img> underlay: visible while Konva decodes the blob URL into its
  // own HTMLImageElement and waits for the Stage's ResizeObserver to fire.
  // Without this the user sees a black background between Suspense resolving
  // and the KonvaImage actually rendering. Once `image` lands, hide the
  // underlay so applied filters/adjustments aren't doubled by the unfiltered
  // copy bleeding through Konva's transparent canvas.
  const showUnderlay = !!imageUrl && !image;

  useEffect(() => {
    if (stageSize.width > 0 && stageSize.height > 0) {
      onStageSize?.(stageSize);
    }
  }, [stageSize, onStageSize]);

  // Auto-initialize cropRect when the crop tool activates without an existing
  // rect. Default = centered, 80% of stage dimensions, respecting cropAspectRatio
  // if set (rect aspect = min of stage-fit + crop-lock). Without this, clicking
  // the crop button activates the tool but leaves the overlay invisible because
  // it gates on `cropRect != null`.
  useEffect(() => {
    if (!cropActive) return;
    if (cropRect) return;
    if (stageSize.width <= 0 || stageSize.height <= 0) return;
    if (!onCropChange) return;
    const sw = stageSize.width;
    const sh = stageSize.height;
    let rw = sw * 0.8;
    let rh = sh * 0.8;
    if (cropAspectRatio && cropAspectRatio > 0) {
      // Fit the largest centered rect with cropAspectRatio inside 80%-of-stage.
      const boxAspect = rw / rh;
      if (boxAspect > cropAspectRatio) {
        rw = rh * cropAspectRatio;
      } else {
        rh = rw / cropAspectRatio;
      }
    }
    onCropChange({
      x: (sw - rw) / 2,
      y: (sh - rh) / 2,
      width: rw,
      height: rh,
    });
  }, [cropActive, cropRect, stageSize, cropAspectRatio, onCropChange]);

  // Apply filter chain + adjustments to the image node.
  // Konva requires .cache() before filters take effect. Re-cache when the
  // image source changes; re-apply filter params on every change.
  useEffect(() => {
    const node = imageNodeRef.current;
    if (!node || !image) return;
    const filterChain = buildKonvaFilterChain(
      activeFilter ?? null,
      adjustments,
    );
    node.cache();
    // The Konva.Filters array type is loose; chain is a list of filter fns.
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    node.filters(filterChain as any);
    applyFilterParams(node, activeFilter ?? null, adjustments);
    node.getLayer()?.batchDraw();
  }, [image, activeFilter, adjustments]);

  const textNodeRefs = useRef<Map<string, Konva.Text>>(new Map());
  const stickerNodeRefs = useRef<Map<string, Konva.Image>>(new Map());

  // Attach the Transformer to the currently-selected node (text or sticker).
  useEffect(() => {
    const t = selection.transformerRef.current;
    if (!t) return;
    let node: Konva.Node | undefined;
    if (selectedTextId) {
      node = textNodeRefs.current.get(selectedTextId);
    } else if (selectedStickerId) {
      node = stickerNodeRefs.current.get(selectedStickerId);
    }
    if (node) {
      t.nodes([node]);
    } else {
      t.nodes([]);
    }
    t.getLayer()?.batchDraw();
  }, [
    selectedTextId,
    selectedStickerId,
    textOverlays,
    stickers,
    selection.transformerRef,
  ]);

  // Click on bare Stage background → clear all selection.
  const handleStageMouseDown = (e: Konva.KonvaEventObject<MouseEvent>) => {
    if (isDrawing) {
      // Drawing intercepts everything — see handleStagePointerDown below.
      return;
    }
    if (e.target === e.target.getStage()) {
      onTextSelect?.(null);
      onStickerSelect?.(null);
      selection.clear();
    }
  };

  // Drawing-mode pointer pipeline. We read the cursor position from the
  // Stage so it's already in stage coordinates (not page coordinates).
  const handleStagePointerDown = (
    e: Konva.KonvaEventObject<PointerEvent>,
  ) => {
    if (!isDrawing) return;
    const stage = e.target.getStage();
    // getRelativePointerPosition returns coords AFTER the Stage's own scale +
    // position transform, which is what we want — strokes stick to the image
    // regardless of zoom/pan state.
    const pos = stage?.getRelativePointerPosition();
    if (pos) onDrawBegin?.(pos.x, pos.y);
  };

  const handleStagePointerMove = (
    e: Konva.KonvaEventObject<PointerEvent>,
  ) => {
    if (!isDrawing || !currentDrawingStroke) return;
    const stage = e.target.getStage();
    // getRelativePointerPosition returns coords AFTER the Stage's own scale +
    // position transform, which is what we want — strokes stick to the image
    // regardless of zoom/pan state.
    const pos = stage?.getRelativePointerPosition();
    if (pos) onDrawExtend?.(pos.x, pos.y);
  };

  const handleStagePointerUp = () => {
    if (!isDrawing) return;
    onDrawEnd?.();
  };

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full h-full overflow-hidden touch-none",
        className,
      )}
      style={{ background }}
      onPointerDown={panZoom.handlers.onPointerDown}
      onPointerMove={panZoom.handlers.onPointerMove}
      onPointerUp={panZoom.handlers.onPointerUp}
      onPointerCancel={panZoom.handlers.onPointerCancel}
    >
      {/* Instant-photo underlay — see `showUnderlay` above. */}
      {showUnderlay ? (
        <img
          src={imageUrl ?? undefined}
          alt=""
          draggable={false}
          className="absolute inset-0 w-full h-full object-contain pointer-events-none"
        />
      ) : null}

      {/* Video drafts render as plain <video> until C7+ wires overlays. */}
      {videoUrl ? (
        <video
          src={videoUrl}
          autoPlay
          loop
          muted
          playsInline
          className="absolute inset-0 w-full h-full object-contain"
        />
      ) : null}

      {/* Stage requires non-zero dimensions; render only after size is measured. */}
      {stageSize.width > 0 && stageSize.height > 0 ? (
        <Stage
          ref={(s) => {
            stageRef.current = s;
            onStageReady?.(s);
          }}
          width={stageSize.width}
          height={stageSize.height}
          scaleX={panZoom.transform.scale}
          scaleY={panZoom.transform.scale}
          x={panZoom.transform.x}
          y={panZoom.transform.y}
          onMouseDown={handleStageMouseDown}
          onTouchStart={handleStageMouseDown as unknown as (e: Konva.KonvaEventObject<TouchEvent>) => void}
          onPointerDown={handleStagePointerDown}
          onPointerMove={handleStagePointerMove}
          onPointerUp={handleStagePointerUp}
          onPointerCancel={handleStagePointerUp}
          className="absolute inset-0"
          style={isDrawing ? { cursor: "crosshair" } : undefined}
        >
          {/* image layer */}
          <Layer listening={false}>
            {image && imageUrl ? (
              <KonvaImage
                ref={imageNodeRef}
                image={image}
                x={fit.x}
                y={fit.y}
                width={fit.width}
                height={fit.height}
              />
            ) : null}
          </Layer>
          {/* drawing layer (C10) */}
          <Layer listening={false}>
            {drawingStrokes?.map((stroke) => (
              <KonvaLine
                key={stroke.id}
                points={stroke.points}
                stroke={stroke.color}
                strokeWidth={stroke.brushSize}
                lineCap="round"
                lineJoin="round"
                tension={0.4}
                globalCompositeOperation={
                  stroke.mode === "erase"
                    ? "destination-out"
                    : "source-over"
                }
              />
            ))}
            {currentDrawingStroke ? (
              <KonvaLine
                key="current"
                points={currentDrawingStroke.points}
                stroke={currentDrawingStroke.color}
                strokeWidth={currentDrawingStroke.brushSize}
                lineCap="round"
                lineJoin="round"
                tension={0.4}
                globalCompositeOperation={
                  currentDrawingStroke.mode === "erase"
                    ? "destination-out"
                    : "source-over"
                }
              />
            ) : null}
          </Layer>
          {/* sticker layer (C9) */}
          <Layer>
            {stickers?.map((placed) => {
              const option = resolveSticker?.(placed.stickerId);
              if (!option) return null;
              return (
                <PlacedStickerImage
                  key={placed.id}
                  placed={placed}
                  option={option}
                  onMount={(node) => {
                    if (node) stickerNodeRefs.current.set(placed.id, node);
                    else stickerNodeRefs.current.delete(placed.id);
                  }}
                  onSelect={() => onStickerSelect?.(placed.id)}
                  onChange={onStickerChange}
                />
              );
            })}
          </Layer>
          {/* text layer (C8) */}
          <Layer>
            {textOverlays?.map((overlay) => (
              <KonvaText
                key={overlay.id}
                ref={(node) => {
                  if (node) textNodeRefs.current.set(overlay.id, node);
                  else textNodeRefs.current.delete(overlay.id);
                }}
                x={overlay.x}
                y={overlay.y}
                text={overlay.text}
                fontFamily={overlay.fontFamily}
                fontSize={overlay.fontSize}
                fill={overlay.fill}
                align={overlay.align}
                rotation={overlay.rotation}
                scaleX={overlay.scale}
                scaleY={overlay.scale}
                draggable
                onMouseDown={(e) => {
                  e.cancelBubble = true;
                  onTextSelect?.(overlay.id);
                }}
                onTouchStart={(e) => {
                  e.cancelBubble = true;
                  onTextSelect?.(overlay.id);
                }}
                onDragEnd={(e) => {
                  onTextChange?.({
                    ...overlay,
                    x: e.target.x(),
                    y: e.target.y(),
                  });
                }}
                onTransformEnd={(e) => {
                  const node = e.target as Konva.Text;
                  const nextScale = node.scaleX();
                  onTextChange?.({
                    ...overlay,
                    x: node.x(),
                    y: node.y(),
                    rotation: node.rotation(),
                    scale: nextScale,
                  });
                }}
              />
            ))}
          </Layer>
          {/* ui layer — Transformer attached on selection */}
          <Layer>
            <Transformer
              ref={selection.transformerRef}
              rotateEnabled
              keepRatio={false}
              boundBoxFunc={(_oldBox, newBox) => {
                // Prevent degenerate negative-size handles.
                if (newBox.width < 8 || newBox.height < 8) return _oldBox;
                return newBox;
              }}
            />
          </Layer>
        </Stage>
      ) : null}

      {/* Reset-zoom CTA — only visible when zoomed/panned, hidden during crop */}
      {!panZoom.isIdentity && !cropActive ? (
        <Button
          type="button"
          variant="secondary"
          size="sm"
          onClick={panZoom.reset}
          aria-label="Reset zoom"
          className="absolute top-3 left-3 z-20 gap-1.5 bg-black/60 backdrop-blur-md text-white hover:bg-black/80 hover:text-white"
        >
          <Maximize2 className="size-3.5" />
          <span className="text-xs font-mono tabular-nums">
            {Math.round(panZoom.transform.scale * 100)}%
          </span>
        </Button>
      ) : null}

      {/* Crop overlay (DOM over the Konva canvas). C11. */}
      {cropActive && cropRect && stageSize.width > 0 ? (
        <CropOverlay
          rect={cropRect}
          stageWidth={stageSize.width}
          stageHeight={stageSize.height}
          aspectRatio={cropAspectRatio ?? null}
          onChange={onCropChange}
        />
      ) : null}
    </div>
  );
}

// ─── Crop overlay (DOM) ───────────────────────────────────────────────

interface CropOverlayProps {
  rect: CropRect;
  stageWidth: number;
  stageHeight: number;
  aspectRatio: number | null;
  onChange?: (next: CropRect) => void;
}

const HANDLE_SIZE = 14;
const MIN_CROP = 40;

function CropOverlay({
  rect,
  stageWidth,
  stageHeight,
  aspectRatio,
  onChange,
}: CropOverlayProps) {
  const dragStateRef = useRef<{
    mode: "move" | "ne" | "nw" | "se" | "sw";
    startX: number;
    startY: number;
    startRect: CropRect;
  } | null>(null);

  const beginDrag = (
    mode: "move" | "ne" | "nw" | "se" | "sw",
  ) => (e: React.PointerEvent) => {
    e.stopPropagation();
    e.currentTarget.setPointerCapture?.(e.pointerId);
    dragStateRef.current = {
      mode,
      startX: e.clientX,
      startY: e.clientY,
      startRect: { ...rect },
    };
  };

  const onPointerMove = (e: React.PointerEvent) => {
    const ds = dragStateRef.current;
    if (!ds || !onChange) return;
    const dx = e.clientX - ds.startX;
    const dy = e.clientY - ds.startY;

    let { x, y, width, height } = ds.startRect;
    const r = aspectRatio; // null = free

    if (ds.mode === "move") {
      x = clamp(ds.startRect.x + dx, 0, stageWidth - ds.startRect.width);
      y = clamp(ds.startRect.y + dy, 0, stageHeight - ds.startRect.height);
    } else {
      // Resize from a corner. Compute signed "growth" for each axis (positive
      // = corner drag enlarges the rect). When aspect-locked, the rect must
      // stay locked end-to-end — including when it hits a stage edge: growth
      // stops cleanly, never breaks ratio. We compute max-allowable next
      // dimensions given the anchor position + stage bounds, then clamp the
      // drive to the most-restrictive of (candidate-from-drag, max-from-X,
      // max-from-Y-mapped-through-r). When free, axes are independent.
      const growX =
        ds.mode === "se" || ds.mode === "ne" ? dx : -dx;
      const growY =
        ds.mode === "se" || ds.mode === "sw" ? dy : -dy;
      // Max additional growth allowed in each axis, given the anchor.
      const maxGrowX =
        ds.mode === "ne" || ds.mode === "se"
          ? stageWidth - (ds.startRect.x + ds.startRect.width)
          : ds.startRect.x;
      const maxGrowY =
        ds.mode === "sw" || ds.mode === "se"
          ? stageHeight - (ds.startRect.y + ds.startRect.height)
          : ds.startRect.y;
      const maxNextW = ds.startRect.width + maxGrowX;
      const maxNextH = ds.startRect.height + maxGrowY;

      let nextWidth: number;
      let nextHeight: number;
      if (r) {
        // User drives EITHER axis. Pick the axis with larger signed growth.
        const xEquivFromY = growY * r;
        const drive =
          Math.abs(xEquivFromY) > Math.abs(growX) ? xEquivFromY : growX;
        let candidateW = ds.startRect.width + drive;
        // Aspect-respecting upper bound: width can't exceed maxNextW OR
        // maxNextH * r (whichever binds first). Lower bound: MIN_CROP.
        const aspectCappedMaxW = Math.min(maxNextW, maxNextH * r);
        candidateW = Math.min(candidateW, aspectCappedMaxW);
        candidateW = Math.max(candidateW, MIN_CROP);
        // Same for shrink direction — width derived height must be >= MIN_CROP.
        candidateW = Math.max(candidateW, MIN_CROP * r);
        nextWidth = candidateW;
        nextHeight = nextWidth / r;
      } else {
        // Free resize — each axis clamped independently.
        nextWidth = Math.max(
          MIN_CROP,
          Math.min(ds.startRect.width + growX, maxNextW),
        );
        nextHeight = Math.max(
          MIN_CROP,
          Math.min(ds.startRect.height + growY, maxNextH),
        );
      }

      // Anchor: the corner opposite to the dragged one stays fixed.
      if (ds.mode === "nw" || ds.mode === "sw") {
        x = ds.startRect.x + (ds.startRect.width - nextWidth);
      }
      if (ds.mode === "nw" || ds.mode === "ne") {
        y = ds.startRect.y + (ds.startRect.height - nextHeight);
      }

      // Stage-bound clamp (safety; aspect-respecting cap above should make
      // these no-ops in normal cases).
      x = clamp(x, 0, stageWidth - nextWidth);
      y = clamp(y, 0, stageHeight - nextHeight);

      width = nextWidth;
      height = nextHeight;
    }

    onChange({ x, y, width, height });
  };

  const endDrag = () => {
    dragStateRef.current = null;
  };

  return (
    <div
      className="absolute inset-0 pointer-events-none"
      style={{ width: stageWidth, height: stageHeight }}
      onPointerMove={onPointerMove}
      onPointerUp={endDrag}
      onPointerCancel={endDrag}
    >
      {/* Dim 4 quadrants outside the crop rect */}
      <div
        className="absolute inset-x-0 top-0 bg-black/60"
        style={{ height: rect.y }}
      />
      <div
        className="absolute inset-x-0 bottom-0 bg-black/60"
        style={{ height: stageHeight - rect.y - rect.height }}
      />
      <div
        className="absolute left-0 bg-black/60"
        style={{
          top: rect.y,
          height: rect.height,
          width: rect.x,
        }}
      />
      <div
        className="absolute right-0 bg-black/60"
        style={{
          top: rect.y,
          height: rect.height,
          width: stageWidth - rect.x - rect.width,
        }}
      />

      {/* Crop frame (movable) */}
      <div
        className="absolute border-2 border-white pointer-events-auto cursor-move"
        style={{
          left: rect.x,
          top: rect.y,
          width: rect.width,
          height: rect.height,
        }}
        onPointerDown={beginDrag("move")}
      >
        {/* Rule-of-thirds grid */}
        <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none">
          {Array.from({ length: 9 }).map((_, i) => (
            <div key={i} className="border border-white/20" />
          ))}
        </div>

        {/* Corner handles */}
        {(["nw", "ne", "sw", "se"] as const).map((corner) => (
          <button
            type="button"
            key={corner}
            onPointerDown={beginDrag(corner)}
            className="absolute bg-white rounded-full shadow"
            style={{
              width: HANDLE_SIZE,
              height: HANDLE_SIZE,
              left:
                corner === "nw" || corner === "sw"
                  ? -HANDLE_SIZE / 2
                  : undefined,
              right:
                corner === "ne" || corner === "se"
                  ? -HANDLE_SIZE / 2
                  : undefined,
              top:
                corner === "nw" || corner === "ne"
                  ? -HANDLE_SIZE / 2
                  : undefined,
              bottom:
                corner === "sw" || corner === "se"
                  ? -HANDLE_SIZE / 2
                  : undefined,
              cursor:
                corner === "nw" || corner === "se"
                  ? "nwse-resize"
                  : "nesw-resize",
            }}
            aria-label={`Resize ${corner.toUpperCase()}`}
          />
        ))}
      </div>
    </div>
  );
}

function clamp(v: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, v));
}

// ─── Sticker rendering ────────────────────────────────────────────────

interface PlacedStickerImageProps {
  placed: PlacedSticker;
  option: StickerOption;
  onMount: (node: Konva.Image | null) => void;
  onSelect: () => void;
  onChange?: (next: PlacedSticker) => void;
}

function PlacedStickerImage({
  placed,
  option,
  onMount,
  onSelect,
  onChange,
}: PlacedStickerImageProps) {
  const [image] = useImage(option.src);
  if (!image) return null;
  return (
    <KonvaImage
      ref={(n) => onMount(n)}
      image={image}
      x={placed.x}
      y={placed.y}
      width={option.width ?? 128}
      height={option.height ?? 128}
      offsetX={(option.width ?? 128) / 2}
      offsetY={(option.height ?? 128) / 2}
      rotation={placed.rotation}
      scaleX={placed.scale}
      scaleY={placed.scale}
      draggable
      onMouseDown={(e) => {
        e.cancelBubble = true;
        onSelect();
      }}
      onTouchStart={(e) => {
        e.cancelBubble = true;
        onSelect();
      }}
      onDragEnd={(e) => {
        onChange?.({
          ...placed,
          x: e.target.x(),
          y: e.target.y(),
        });
      }}
      onTransformEnd={(e) => {
        const node = e.target as Konva.Image;
        onChange?.({
          ...placed,
          x: node.x(),
          y: node.y(),
          rotation: node.rotation(),
          scale: node.scaleX(),
        });
      }}
    />
  );
}

// ─── Helpers ──────────────────────────────────────────────────────────

interface Size {
  width: number;
  height: number;
}

/** Load an image element + report its natural size. Returns [image, size]. */
function useImage(
  src: string | null,
): [HTMLImageElement | null, Size] {
  const [image, setImage] = useState<HTMLImageElement | null>(null);
  const [size, setSize] = useState<Size>({ width: 0, height: 0 });

  useEffect(() => {
    if (!src) {
      setImage(null);
      setSize({ width: 0, height: 0 });
      return;
    }
    const img = new window.Image();
    img.crossOrigin = "anonymous";
    let cancelled = false;
    img.onload = () => {
      if (cancelled) return;
      setImage(img);
      setSize({ width: img.naturalWidth, height: img.naturalHeight });
    };
    img.onerror = () => {
      if (cancelled) return;
      setImage(null);
    };
    img.src = src;
    return () => {
      cancelled = true;
    };
  }, [src]);

  return [image, size];
}

// ─── Filter helpers ───────────────────────────────────────────────────

const KONVA_FILTER_MAP: Record<string, KonvaFilter | undefined> = {
  Brighten: Konva.Filters.Brighten,
  Contrast: Konva.Filters.Contrast,
  HSL: Konva.Filters.HSL,
  Sepia: Konva.Filters.Sepia,
  Grayscale: Konva.Filters.Grayscale,
  Blur: Konva.Filters.Blur,
  Noise: Konva.Filters.Noise,
};

/** Build the KonvaFilter array for the active preset + adjust sliders. */
function buildKonvaFilterChain(
  preset: FilterPreset | null,
  adjustments?: ImageAdjustments,
): KonvaFilter[] {
  const seen = new Set<string>();
  const out: KonvaFilter[] = [];
  const add = (name: string) => {
    if (seen.has(name)) return;
    const fn = KONVA_FILTER_MAP[name];
    if (!fn) return;
    seen.add(name);
    out.push(fn);
  };
  if (preset) {
    for (const spec of preset.konvaFilters) add(spec.name);
  }
  // Always include the adjustment filters so the sliders work over any preset.
  if (adjustments) {
    if (adjustments.brightness !== 0) add("Brighten");
    if (adjustments.contrast !== 0) add("Contrast");
    if (adjustments.saturation !== 0) add("HSL");
    if (adjustments.blur > 0) add("Blur");
  }
  return out;
}

/** Push numeric filter params onto the image node. */
function applyFilterParams(
  node: Konva.Image,
  preset: FilterPreset | null,
  adjustments?: ImageAdjustments,
) {
  // Reset to neutral before applying.
  node.brightness(0);
  node.contrast(0);
  node.saturation(0);
  node.hue(0);
  node.blurRadius(0);

  // Apply preset values first.
  if (preset) {
    for (const spec of preset.konvaFilters) {
      const p = spec.params ?? {};
      if (spec.name === "Brighten" && p.brightness !== undefined) {
        node.brightness(p.brightness);
      } else if (spec.name === "Contrast" && p.contrast !== undefined) {
        node.contrast(p.contrast);
      } else if (spec.name === "HSL") {
        if (p.saturation !== undefined) node.saturation(p.saturation);
        if (p.hue !== undefined) node.hue(p.hue);
      } else if (spec.name === "Blur" && p.blurRadius !== undefined) {
        node.blurRadius(p.blurRadius);
      }
    }
  }
  // Adjustments add on top of preset values.
  if (adjustments) {
    node.brightness(node.brightness() + adjustments.brightness);
    node.contrast(node.contrast() + adjustments.contrast);
    node.saturation(node.saturation() + adjustments.saturation);
    if (adjustments.blur > 0) node.blurRadius(adjustments.blur);
  }
}

/** Object-fit: contain inside the stage. */
function fitInto(
  source: Size,
  target: StageSize,
): { x: number; y: number; width: number; height: number } {
  if (
    source.width === 0 ||
    source.height === 0 ||
    target.width === 0 ||
    target.height === 0
  ) {
    return { x: 0, y: 0, width: 0, height: 0 };
  }
  const scale = Math.min(
    target.width / source.width,
    target.height / source.height,
  );
  const width = source.width * scale;
  const height = source.height * scale;
  const x = (target.width - width) / 2;
  const y = (target.height - height) / 2;
  return { x, y, width, height };
}

"use client";

import {
  Crop,
  Palette,
  Sliders,
  Smile,
  Type,
  Wand,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { EditTool, StoryComposer01Labels } from "../types";

export interface EditorToolbarProps {
  activeTool: EditTool | null;
  enabledTools: EditTool[];
  /** Tools that aren't shipped yet — render disabled. */
  pendingTools?: EditTool[];
  labels: Required<StoryComposer01Labels>;
  onSelect: (tool: EditTool | null) => void;
  className?: string;
}

interface ToolConfig {
  key: EditTool;
  icon: React.ComponentType<{ className?: string }>;
  label: (labels: Required<StoryComposer01Labels>) => string;
}

const TOOL_ORDER: ToolConfig[] = [
  { key: "text", icon: Type, label: (l) => l.toolText },
  { key: "draw", icon: Wand, label: (l) => l.toolDraw },
  { key: "stickers", icon: Smile, label: (l) => l.toolStickers },
  { key: "filters", icon: Palette, label: (l) => l.toolFilters },
  { key: "adjust", icon: Sliders, label: (l) => l.toolAdjust },
  { key: "crop", icon: Crop, label: (l) => l.toolCrop },
];

export function EditorToolbar({
  activeTool,
  enabledTools,
  pendingTools = [],
  labels,
  onSelect,
  className,
}: EditorToolbarProps) {
  const visible = TOOL_ORDER.filter((t) => enabledTools.includes(t.key));

  return (
    <div
      role="toolbar"
      aria-label="Edit tools"
      className={cn(
        "flex items-center justify-around gap-1 rounded-2xl",
        "bg-black/70 backdrop-blur-md px-1 py-1.5 text-white",
        className,
      )}
    >
      {visible.map((tool) => {
        const Icon = tool.icon;
        const isActive = activeTool === tool.key;
        const isPending = pendingTools.includes(tool.key);
        return (
          <Button
            key={tool.key}
            type="button"
            variant="ghost"
            size="sm"
            disabled={isPending}
            aria-pressed={isActive}
            aria-label={tool.label(labels)}
            onClick={() => onSelect(isActive ? null : tool.key)}
            className={cn(
              "flex flex-col items-center gap-0.5 h-auto px-2 py-1.5 text-[10px] text-white/80 hover:bg-white/10 hover:text-white",
              isActive && "text-white bg-white/15",
              isPending && "opacity-40",
            )}
          >
            <Icon className="size-5" />
            <span>{tool.label(labels)}</span>
          </Button>
        );
      })}
    </div>
  );
}

"use client";

import { ToggleGroup, ToggleGroupItem } from "@/components/ui/toggle-group";
import { cn } from "@/lib/utils";
import type { ComposerMode, StoryComposer01Labels } from "../types";

export interface ModeTogglePillProps {
  mode: ComposerMode;
  visibleModes: ComposerMode[];
  labels: Required<StoryComposer01Labels>;
  onModeChange: (mode: ComposerMode) => void;
  className?: string;
}

const ORDER: ComposerMode[] = ["photo", "video", "text"];

export function ModeTogglePill({
  mode,
  visibleModes,
  labels,
  onModeChange,
  className,
}: ModeTogglePillProps) {
  if (visibleModes.length < 2) return null;

  const orderedVisible = ORDER.filter((m) => visibleModes.includes(m));

  return (
    <ToggleGroup
      type="single"
      value={mode}
      onValueChange={(next) => {
        // ToggleGroup emits "" when the active item is re-tapped — ignore.
        if (next && orderedVisible.includes(next as ComposerMode)) {
          onModeChange(next as ComposerMode);
        }
      }}
      className={cn(
        "inline-flex rounded-full bg-black/40 backdrop-blur-md p-1 text-white",
        className,
      )}
    >
      {orderedVisible.map((m) => (
        <ToggleGroupItem
          key={m}
          value={m}
          aria-label={labelFor(m, labels)}
          className={cn(
            "rounded-full px-4 py-1.5 text-xs font-medium tracking-wide uppercase",
            "text-white/70 data-[state=on]:bg-white data-[state=on]:text-black",
            "hover:bg-white/10 hover:text-white",
            "data-[state=on]:hover:bg-white data-[state=on]:hover:text-black",
            "transition-colors",
          )}
        >
          {labelFor(m, labels)}
        </ToggleGroupItem>
      ))}
    </ToggleGroup>
  );
}

function labelFor(
  mode: ComposerMode,
  labels: Required<StoryComposer01Labels>,
): string {
  switch (mode) {
    case "photo":
      return labels.modePhoto;
    case "video":
      return labels.modeVideo;
    case "text":
      return labels.modeText;
  }
}

"use client";

import { useCallback, useRef, type PointerEvent } from "react";
import { cn } from "@/lib/utils";

export interface ShutterButtonProps {
  mode: "photo" | "video";
  /** Photo-mode tap. Ignored when mode="video". */
  onPress?: () => void;
  /** Video-mode start. Called for both long-press hold and tap-to-start. */
  onStart?: () => void;
  /** Video-mode stop. Called on long-press release OR tap-to-stop. */
  onStop?: () => void;
  /** Recording in-flight (drives ring fill + inner shape). */
  isRecording?: boolean;
  /** 0..1 — fraction of maxVideoDuration elapsed. Drives ring conic-gradient. */
  recordProgress?: number;
  disabled?: boolean;
  ariaLabel: string;
  className?: string;
}

const LONG_PRESS_THRESHOLD_MS = 250;

/**
 * Shutter behavior matrix (Instagram parity):
 *
 *   Mode photo + tap     → onPress
 *   Mode video + tap     → onStart (then a later tap → onStop)
 *   Mode video + hold    → onStart on down, onStop on up
 */
export function ShutterButton({
  mode,
  onPress,
  onStart,
  onStop,
  isRecording = false,
  recordProgress = 0,
  disabled = false,
  ariaLabel,
  className,
}: ShutterButtonProps) {
  const pressStartRef = useRef<number>(0);
  const startedThisPressRef = useRef(false);

  const handlePointerDown = useCallback(
    (e: PointerEvent<HTMLButtonElement>) => {
      if (disabled) return;
      e.currentTarget.setPointerCapture?.(e.pointerId);
      pressStartRef.current = Date.now();
      if (mode === "photo") {
        startedThisPressRef.current = false;
        return;
      }
      if (!isRecording) {
        startedThisPressRef.current = true;
        onStart?.();
      } else {
        startedThisPressRef.current = false;
      }
    },
    [disabled, mode, isRecording, onStart],
  );

  const handlePointerUp = useCallback(
    (e: PointerEvent<HTMLButtonElement>) => {
      if (disabled) return;
      e.currentTarget.releasePointerCapture?.(e.pointerId);
      const elapsed = Date.now() - pressStartRef.current;

      if (mode === "photo") {
        onPress?.();
        return;
      }

      const wasHold = elapsed >= LONG_PRESS_THRESHOLD_MS;
      if (wasHold) {
        onStop?.();
      } else if (!startedThisPressRef.current) {
        // Tap on already-recording shutter → stop (tap-to-toggle stop)
        onStop?.();
      }
      // else: tap started recording this press → leave running (tap-to-toggle start)
      startedThisPressRef.current = false;
    },
    [disabled, mode, onPress, onStop],
  );

  const handlePointerCancel = useCallback(() => {
    // Treat cancellation as a stop if we started recording.
    if (mode === "video" && isRecording && startedThisPressRef.current) {
      onStop?.();
      startedThisPressRef.current = false;
    }
  }, [mode, isRecording, onStop]);

  // Ring fill via conic-gradient when recording.
  const ringStyle =
    mode === "video" && isRecording
      ? {
          background: `conic-gradient(#ef4444 ${recordProgress * 360}deg, rgba(255,255,255,0.3) ${recordProgress * 360}deg)`,
        }
      : undefined;

  return (
    <button
      type="button"
      onPointerDown={handlePointerDown}
      onPointerUp={handlePointerUp}
      onPointerCancel={handlePointerCancel}
      disabled={disabled}
      aria-label={ariaLabel}
      aria-pressed={mode === "video" ? isRecording : undefined}
      className={cn(
        // Responsive size — min 48px on narrow viewports, max 68px on wide.
        "relative grid place-items-center size-[clamp(3rem,12vw,4.25rem)] rounded-full",
        "transition-transform active:scale-95",
        "disabled:opacity-40 disabled:cursor-not-allowed",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-transparent",
        className,
      )}
      style={ringStyle}
    >
      {/* Outer ring (idle white border; conic on record) */}
      {mode === "video" && isRecording ? (
        // Filled ring is the gradient on the button itself; inner stop-square sits inside
        <span className="grid place-items-center size-[80%] rounded-full bg-black/60">
          <span className="size-[36%] rounded-md bg-red-500" />
        </span>
      ) : (
        <span
          className={cn(
            "size-full rounded-full ring-4 ring-white/30 ring-offset-2 ring-offset-transparent grid place-items-center",
            "bg-white",
          )}
        >
          {mode === "video" ? (
            <span className="size-[30%] rounded-full bg-red-500" />
          ) : null}
        </span>
      )}
      <span className="sr-only">{ariaLabel}</span>
    </button>
  );
}

"use client";

import { forwardRef, useState } from "react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { ColorSwatchPicker } from "./color-swatch-picker";
import type { GradientPreset, FontOption } from "../../media-editor-01";
import type { StoryComposer01Labels } from "../types";

export interface TextOnlyCanvasProps {
  gradients: GradientPreset[];
  fonts: FontOption[];
  colorPresets: string[];
  labels: Required<StoryComposer01Labels>;
  className?: string;
}

export interface TextOnlyCanvasState {
  text: string;
  fontFamily: string;
  textColor: string;
  gradientId: string;
}

/**
 * Text-only mode capture surface.
 *
 * Rendered as a styled DOM element (NOT Konva) so `exportTextOnlyBlob()`
 * can rasterise it via the SVG-foreignObject technique on publish. The
 * forwardRef exposes the canvas <div> element so the publish path can
 * pass it to the exporter.
 */
export const TextOnlyCanvas = forwardRef<
  HTMLDivElement,
  TextOnlyCanvasProps & {
    value: TextOnlyCanvasState;
    onChange: (next: TextOnlyCanvasState) => void;
  }
>(function TextOnlyCanvas(
  { gradients, fonts, colorPresets, labels, value, onChange, className },
  ref,
) {
  const [pickerOpen, setPickerOpen] = useState<"gradient" | "font" | null>(
    null,
  );

  const activeGradient =
    gradients.find((g) => g.id === value.gradientId) ?? gradients[0];

  const update = (patch: Partial<TextOnlyCanvasState>) =>
    onChange({ ...value, ...patch });

  return (
    <div
      className={cn("relative flex-1 flex flex-col overflow-hidden", className)}
    >
      {/* Render surface — exported as PNG on publish */}
      <div
        ref={ref}
        className="absolute inset-0 grid place-items-center px-8"
        style={{ background: activeGradient?.background ?? "#000" }}
      >
        <textarea
          value={value.text}
          onChange={(e) => update({ text: e.target.value })}
          placeholder={labels.textPlaceholder}
          rows={3}
          aria-label={labels.textPlaceholder}
          className="w-full max-w-[20rem] resize-none bg-transparent text-center placeholder:text-current/40 focus:outline-none"
          style={{
            color: value.textColor,
            fontFamily: value.fontFamily,
            fontSize: "clamp(1.5rem, 7vw, 3rem)",
            lineHeight: 1.2,
            fontWeight: 600,
            textShadow: "0 2px 8px rgba(0,0,0,0.25)",
          }}
        />
      </div>

      {/* Bottom control bar — gradient picker + font + color */}
      <div
        className="absolute left-0 right-0 z-20 flex flex-col gap-2 px-3"
        style={{
          bottom: "max(1.25rem, env(safe-area-inset-bottom))",
        }}
      >
        {pickerOpen === "gradient" ? (
          <div className="flex items-center gap-2 overflow-x-auto rounded-2xl bg-black/70 backdrop-blur-md p-2">
            {gradients.map((g) => {
              const isActive = g.id === value.gradientId;
              return (
                <button
                  key={g.id}
                  type="button"
                  onClick={() => update({ gradientId: g.id })}
                  aria-label={g.label}
                  aria-pressed={isActive}
                  className={cn(
                    "flex-none size-10 rounded-full ring-2 transition-shadow",
                    isActive ? "ring-white" : "ring-transparent",
                  )}
                  style={{ background: g.background }}
                />
              );
            })}
          </div>
        ) : null}

        <div className="flex items-center justify-between gap-2 rounded-2xl bg-black/70 backdrop-blur-md p-2 text-white">
          <Button
            variant="ghost"
            size="sm"
            onClick={() =>
              setPickerOpen((p) => (p === "gradient" ? null : "gradient"))
            }
            aria-pressed={pickerOpen === "gradient"}
            className="text-xs gap-2 text-white hover:bg-white/10 hover:text-white"
          >
            <span
              className="inline-block size-4 rounded-full ring-2 ring-white/40"
              style={{ background: activeGradient?.background ?? "#000" }}
              aria-hidden
            />
            <span>Background</span>
          </Button>

          <div className="flex items-center gap-2">
            <select
              value={value.fontFamily}
              onChange={(e) => update({ fontFamily: e.target.value })}
              aria-label={labels.textFontFamily}
              className="h-7 rounded-md bg-black/40 border border-white/15 px-2 text-xs"
            >
              {fonts.map((font) => (
                <option
                  key={font.id}
                  value={font.family}
                  style={{ fontFamily: font.family }}
                >
                  {font.label}
                </option>
              ))}
            </select>
            <ColorSwatchPicker
              value={value.textColor}
              presets={colorPresets}
              onChange={(c) => update({ textColor: c })}
              ariaLabel={labels.drawColor}
            />
          </div>
        </div>
      </div>
    </div>
  );
});

"use client";

import { useCallback } from "react";
import { Slider } from "@/components/ui/slider";
import { cn } from "@/lib/utils";
import type { ImageAdjustments, StoryComposer01Labels } from "../types";

export interface ToolAdjustSlidersProps {
  value: ImageAdjustments;
  onChange: (next: ImageAdjustments) => void;
  labels: Required<StoryComposer01Labels>;
  className?: string;
}

interface SliderConfig {
  key: keyof ImageAdjustments;
  label: string;
  min: number;
  max: number;
  step: number;
}

export function ToolAdjustSliders({
  value,
  onChange,
  labels,
  className,
}: ToolAdjustSlidersProps) {
  const configs: SliderConfig[] = [
    {
      key: "brightness",
      label: labels.adjustBrightness,
      min: -1,
      max: 1,
      step: 0.05,
    },
    {
      key: "contrast",
      label: labels.adjustContrast,
      min: -100,
      max: 100,
      step: 5,
    },
    {
      key: "saturation",
      label: labels.adjustSaturation,
      min: -2,
      max: 5,
      step: 0.1,
    },
    {
      key: "blur",
      label: labels.adjustBlur,
      min: 0,
      max: 40,
      step: 1,
    },
  ];

  const update = useCallback(
    (key: keyof ImageAdjustments, next: number) => {
      onChange({ ...value, [key]: next });
    },
    [onChange, value],
  );

  return (
    <div
      className={cn(
        "flex flex-col gap-4 p-4 rounded-2xl bg-black/70 backdrop-blur-md text-white",
        className,
      )}
    >
      {configs.map((cfg) => (
        <div key={cfg.key} className="flex flex-col gap-1.5">
          <div className="flex items-center justify-between text-xs">
            <span className="font-medium">{cfg.label}</span>
            <span className="font-mono tabular-nums text-white/60">
              {formatValue(value[cfg.key], cfg.key)}
            </span>
          </div>
          <Slider
            value={[value[cfg.key]]}
            min={cfg.min}
            max={cfg.max}
            step={cfg.step}
            onValueChange={(arr) => update(cfg.key, arr[0] ?? 0)}
            aria-label={cfg.label}
          />
        </div>
      ))}
    </div>
  );
}

function formatValue(v: number, key: keyof ImageAdjustments): string {
  if (key === "contrast" || key === "blur") return String(Math.round(v));
  return v.toFixed(2);
}

