"use client";

import { useEffect, useRef, useState } from "react";
import { cn } from "@/lib/utils";
import type { FilterPreset } from "../types";

export interface ToolFilterStripProps {
  presets: FilterPreset[];
  /** Image URL the thumbnails sample (the captured photo). */
  sourceUrl: string;
  /** Currently-active preset id. null = "original" / no filter. */
  activeId: string | null;
  onSelect: (id: string | null) => void;
  className?: string;
}

interface ThumbnailEntry {
  preset: FilterPreset;
  url: string;
}

const THUMB_SIZE = 56;

/**
 * Horizontal scrollable strip of filter presets, each rendered as a
 * pre-rendered thumbnail of the captured photo with that filter applied.
 *
 * Q-P7a — thumbnails are computed once on edit-mode entry (~1s for ~10
 * filters on a typical 1080p photo). Subsequent taps are instant.
 *
 * For C7 we use CSS-filter approximations (cheap, no Konva), which gives
 * the user a near-WYSIWYG preview. The actual on-stage application
 * (which uses Konva.Filters) is wired in composer-editor.tsx and matches
 * the CSS recipe closely enough for browse-then-confirm UX.
 */
export function ToolFilterStrip({
  presets,
  sourceUrl,
  activeId,
  onSelect,
  className,
}: ToolFilterStripProps) {
  const [thumbs, setThumbs] = useState<ThumbnailEntry[]>([]);
  const cancelledRef = useRef(false);

  useEffect(() => {
    cancelledRef.current = false;
    if (!sourceUrl || presets.length === 0) {
      setThumbs([]);
      return;
    }

    const img = new window.Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      if (cancelledRef.current) return;
      const canvas = document.createElement("canvas");
      canvas.width = THUMB_SIZE;
      canvas.height = THUMB_SIZE;
      const ctx = canvas.getContext("2d");
      if (!ctx) return;

      const drawCovered = () => {
        const ratio = Math.max(
          THUMB_SIZE / img.naturalWidth,
          THUMB_SIZE / img.naturalHeight,
        );
        const w = img.naturalWidth * ratio;
        const h = img.naturalHeight * ratio;
        const x = (THUMB_SIZE - w) / 2;
        const y = (THUMB_SIZE - h) / 2;
        ctx.clearRect(0, 0, THUMB_SIZE, THUMB_SIZE);
        ctx.drawImage(img, x, y, w, h);
      };

      const out: ThumbnailEntry[] = [];
      for (const preset of presets) {
        ctx.filter = cssFilterForPreset(preset);
        drawCovered();
        out.push({ preset, url: canvas.toDataURL("image/jpeg", 0.7) });
      }
      ctx.filter = "none";
      if (!cancelledRef.current) setThumbs(out);
    };
    img.src = sourceUrl;

    return () => {
      cancelledRef.current = true;
    };
  }, [sourceUrl, presets]);

  return (
    <div
      className={cn(
        "flex items-center gap-2 overflow-x-auto overscroll-x-contain",
        "rounded-2xl bg-black/70 backdrop-blur-md p-2 text-white",
        "scrollbar-thin scrollbar-thumb-white/20 scrollbar-track-transparent",
        className,
      )}
    >
      {(thumbs.length > 0
        ? thumbs
        : presets.map((p) => ({ preset: p, url: "" }))
      ).map(({ preset, url }) => {
        const isActive = activeId === preset.id || (!activeId && preset.id === "original");
        return (
          <button
            key={preset.id}
            type="button"
            onClick={() =>
              onSelect(preset.id === "original" ? null : preset.id)
            }
            className={cn(
              "flex-none flex flex-col items-center gap-1 outline-none",
              "focus-visible:ring-2 focus-visible:ring-white rounded-lg",
            )}
            aria-pressed={isActive}
            aria-label={preset.label}
          >
            <div
              className={cn(
                "size-14 rounded-lg overflow-hidden bg-black/60 ring-2 transition-shadow",
                isActive ? "ring-white" : "ring-transparent",
              )}
            >
              {url ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img
                  src={url}
                  alt=""
                  className="w-full h-full object-cover"
                />
              ) : (
                <div className="w-full h-full bg-white/5 animate-pulse" />
              )}
            </div>
            <span className="text-[10px] font-medium uppercase tracking-wider">
              {preset.label}
            </span>
          </button>
        );
      })}
    </div>
  );
}

/**
 * Approximate each Konva filter chain with a CSS `filter:` string for the
 * preview thumbnail. CSS doesn't have a 1:1 mapping, but this approximation
 * is good enough for browse-and-pick UX.
 */
function cssFilterForPreset(preset: FilterPreset): string {
  if (preset.konvaFilters.length === 0) return "none";
  const parts: string[] = [];
  let saturate = 1;
  let brightness = 1;
  let contrast = 1;
  let sepia = 0;
  let hue = 0;
  let grayscale = 0;
  let blur = 0;
  for (const f of preset.konvaFilters) {
    switch (f.name) {
      case "Brighten":
        brightness *= 1 + (f.params?.brightness ?? 0);
        break;
      case "Contrast":
        contrast *= 1 + (f.params?.contrast ?? 0) / 100;
        break;
      case "HSL":
        saturate *= 1 + (f.params?.saturation ?? 0);
        hue += f.params?.hue ?? 0;
        break;
      case "Sepia":
        sepia = Math.min(1, sepia + 0.25);
        break;
      case "Grayscale":
        grayscale = 1;
        break;
      case "Blur":
        blur += f.params?.blurRadius ?? 0;
        break;
    }
  }
  parts.push(`brightness(${brightness.toFixed(2)})`);
  parts.push(`contrast(${contrast.toFixed(2)})`);
  parts.push(`saturate(${Math.max(0, saturate).toFixed(2)})`);
  if (hue !== 0) parts.push(`hue-rotate(${hue}deg)`);
  if (sepia > 0) parts.push(`sepia(${sepia.toFixed(2)})`);
  if (grayscale > 0) parts.push(`grayscale(${grayscale})`);
  if (blur > 0) parts.push(`blur(${blur}px)`);
  return parts.join(" ");
}

"use client";

import { useState } from "react";
import { cn } from "@/lib/utils";
import type { StickerOption, StickerSet } from "../types";

export interface ToolStickerPickerProps {
  sets: StickerSet[];
  onPick: (sticker: StickerOption) => void;
  className?: string;
}

/**
 * Bottom-sheet sticker picker. Top row of category tabs + scrollable grid
 * of stickers from the active set. Tap a sticker → consumer adds it to
 * the stage (center) and selects it for transformer manipulation.
 */
export function ToolStickerPicker({
  sets,
  onPick,
  className,
}: ToolStickerPickerProps) {
  const [activeSetId, setActiveSetId] = useState(sets[0]?.id ?? "");
  const activeSet = sets.find((s) => s.id === activeSetId) ?? sets[0];

  if (!activeSet) return null;

  return (
    <div
      className={cn(
        "flex flex-col gap-2 rounded-2xl bg-black/70 backdrop-blur-md p-3 text-white",
        className,
      )}
    >
      {/* Category tabs */}
      {sets.length > 1 ? (
        <div className="flex items-center gap-1 overflow-x-auto">
          {sets.map((set) => {
            const isActive = set.id === activeSet.id;
            return (
              <button
                key={set.id}
                type="button"
                onClick={() => setActiveSetId(set.id)}
                aria-pressed={isActive}
                className={cn(
                  "flex-none rounded-full px-3 py-1 text-[10px] font-medium tracking-wider uppercase transition-colors",
                  isActive
                    ? "bg-white text-black"
                    : "text-white/70 hover:text-white hover:bg-white/10",
                )}
              >
                {set.label}
              </button>
            );
          })}
        </div>
      ) : null}

      {/* Sticker grid — capped at ~3 rows so the panel doesn't take the whole screen */}
      <div
        className={cn(
          "grid grid-cols-6 gap-2 overflow-y-auto",
          "max-h-[40dvh] sm:max-h-44",
        )}
      >
        {activeSet.stickers.map((sticker) => (
          <button
            key={sticker.id}
            type="button"
            onClick={() => onPick(sticker)}
            aria-label={sticker.alt}
            className="aspect-square rounded-lg bg-white/5 hover:bg-white/15 active:scale-95 transition-transform p-1 grid place-items-center"
          >
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img
              src={sticker.src}
              alt={sticker.alt}
              className="w-full h-full object-contain"
            />
          </button>
        ))}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { AlignCenter, AlignLeft, AlignRight, Trash2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { cn } from "@/lib/utils";
import { ColorSwatchPicker } from "./color-swatch-picker";
import type {
  FontOption,
  StoryComposer01Labels,
  TextOverlay,
} from "../types";

export interface ToolTextInputProps {
  overlay: TextOverlay;
  fonts: FontOption[];
  colorPresets: string[];
  labels: Required<StoryComposer01Labels>;
  onChange: (next: TextOverlay) => void;
  onDelete: () => void;
  className?: string;
}

const MIN_FONT_SIZE = 16;
const MAX_FONT_SIZE = 96;

/**
 * Active-text-overlay editor — text input, font, size, color, align.
 * Mounts when there's a selected text overlay.
 */
export function ToolTextInput({
  overlay,
  fonts,
  colorPresets,
  labels,
  onChange,
  onDelete,
  className,
}: ToolTextInputProps) {
  const textareaRef = useRef<HTMLTextAreaElement | null>(null);

  // Autofocus when a new overlay is selected.
  useEffect(() => {
    textareaRef.current?.focus();
    textareaRef.current?.select();
  }, [overlay.id]);

  const update = (patch: Partial<TextOverlay>) =>
    onChange({ ...overlay, ...patch });

  return (
    <div
      className={cn(
        "flex flex-col gap-3 rounded-2xl bg-black/70 backdrop-blur-md p-3 text-white",
        className,
      )}
    >
      <textarea
        ref={textareaRef}
        value={overlay.text}
        onChange={(e) => update({ text: e.target.value })}
        placeholder={labels.textPlaceholder}
        rows={2}
        className="w-full resize-none rounded-md bg-black/40 border border-white/15 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-white/40"
        style={{ fontFamily: overlay.fontFamily }}
      />

      {/* Font + color + delete */}
      <div className="flex items-center gap-2">
        <label className="sr-only" htmlFor="text-font">
          {labels.textFontFamily}
        </label>
        <select
          id="text-font"
          value={overlay.fontFamily}
          onChange={(e) => update({ fontFamily: e.target.value })}
          className="flex-1 h-8 rounded-md bg-black/40 border border-white/15 px-2 text-xs"
        >
          {fonts.map((font) => (
            <option
              key={font.id}
              value={font.family}
              style={{ fontFamily: font.family }}
            >
              {font.label}
            </option>
          ))}
        </select>

        <ColorSwatchPicker
          value={overlay.fill}
          presets={colorPresets}
          onChange={(color) => update({ fill: color })}
          ariaLabel={labels.drawColor}
        />

        {/* Align toggle */}
        <div className="inline-flex rounded-md bg-black/40 border border-white/15 p-0.5">
          {(["left", "center", "right"] as const).map((align) => (
            <button
              key={align}
              type="button"
              onClick={() => update({ align })}
              aria-label={`${labels.textAlign} ${align}`}
              aria-pressed={overlay.align === align}
              className={cn(
                "p-1 rounded-sm",
                overlay.align === align
                  ? "bg-white text-black"
                  : "text-white/80 hover:text-white",
              )}
            >
              {align === "left" ? (
                <AlignLeft className="size-3.5" />
              ) : align === "center" ? (
                <AlignCenter className="size-3.5" />
              ) : (
                <AlignRight className="size-3.5" />
              )}
            </button>
          ))}
        </div>

        <Button
          variant="ghost"
          size="icon"
          onClick={onDelete}
          aria-label="Delete text"
          className="size-8 text-red-300 hover:bg-red-500/15 hover:text-red-200"
        >
          <Trash2 className="size-4" />
        </Button>
      </div>

      {/* Font size slider */}
      <div className="flex items-center gap-3">
        <span className="text-[10px] uppercase tracking-wider text-white/60 w-10">
          {labels.textFontSize}
        </span>
        <Slider
          value={[overlay.fontSize]}
          min={MIN_FONT_SIZE}
          max={MAX_FONT_SIZE}
          step={1}
          onValueChange={(arr) => update({ fontSize: arr[0] ?? overlay.fontSize })}
          aria-label={labels.textFontSize}
          className="flex-1"
        />
        <span className="text-xs font-mono tabular-nums w-8 text-right">
          {overlay.fontSize}
        </span>
      </div>
    </div>
  );
}

"use client";

import {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
  type PointerEvent,
} from "react";
import { cn } from "@/lib/utils";
import type { StoryComposer01Labels } from "../types";

export interface VideoTrimBarProps {
  /** Source video URL (object URL from a Blob is fine). */
  videoUrl: string;
  /** Trim range in seconds — controlled. */
  startSec: number;
  endSec: number;
  /** Authoritative duration from the source video. */
  durationSec: number;
  /** Number of preview thumbnails to generate (default 8). */
  thumbnailCount?: number;
  labels: Required<StoryComposer01Labels>;
  onChange: (next: { startSec: number; endSec: number }) => void;
  className?: string;
}

interface FrameThumb {
  t: number;
  url: string;
}

const MIN_DURATION_SEC = 0.5;

/**
 * Two-handle trim bar with auto-generated frame previews.
 *
 * Thumbnails are produced once on mount by seeking an off-DOM <video>
 * to N evenly-spaced timestamps and snapping each frame to a canvas.
 */
export function VideoTrimBar({
  videoUrl,
  startSec,
  endSec,
  durationSec,
  thumbnailCount = 8,
  labels,
  onChange,
  className,
}: VideoTrimBarProps) {
  const trackRef = useRef<HTMLDivElement | null>(null);
  const [thumbs, setThumbs] = useState<FrameThumb[]>([]);
  const draggingRef = useRef<"start" | "end" | null>(null);

  // ─── Generate frame thumbnails ──────────────────────────────────────
  useEffect(() => {
    let cancelled = false;
    if (!videoUrl || durationSec <= 0) return;

    const video = document.createElement("video");
    video.src = videoUrl;
    video.crossOrigin = "anonymous";
    video.muted = true;
    video.preload = "auto";
    video.playsInline = true;

    const cleanup = () => {
      video.removeAttribute("src");
      video.load();
    };

    const onLoaded = async () => {
      const canvas = document.createElement("canvas");
      const w = 64;
      const h = 96;
      canvas.width = w;
      canvas.height = h;
      const ctx = canvas.getContext("2d");
      if (!ctx) {
        cleanup();
        return;
      }
      const out: FrameThumb[] = [];
      for (let i = 0; i < thumbnailCount; i++) {
        const t = (i / (thumbnailCount - 1 || 1)) * durationSec;
        await seekTo(video, t);
        if (cancelled) return;
        ctx.drawImage(video, 0, 0, w, h);
        const url = canvas.toDataURL("image/jpeg", 0.6);
        out.push({ t, url });
      }
      if (!cancelled) setThumbs(out);
      cleanup();
    };

    video.addEventListener("loadedmetadata", onLoaded, { once: true });

    return () => {
      cancelled = true;
      video.removeEventListener("loadedmetadata", onLoaded);
      cleanup();
    };
  }, [videoUrl, durationSec, thumbnailCount]);

  // ─── Drag handlers ──────────────────────────────────────────────────
  const positionForX = useCallback(
    (clientX: number): number => {
      const track = trackRef.current;
      if (!track) return 0;
      const rect = track.getBoundingClientRect();
      const ratio = Math.min(1, Math.max(0, (clientX - rect.left) / rect.width));
      return ratio * durationSec;
    },
    [durationSec],
  );

  const handlePointerDown = useCallback(
    (which: "start" | "end") => (e: PointerEvent<HTMLButtonElement>) => {
      e.currentTarget.setPointerCapture?.(e.pointerId);
      draggingRef.current = which;
    },
    [],
  );

  const handlePointerMove = useCallback(
    (e: PointerEvent<HTMLDivElement>) => {
      if (!draggingRef.current) return;
      const next = positionForX(e.clientX);
      if (draggingRef.current === "start") {
        const clamped = Math.min(next, endSec - MIN_DURATION_SEC);
        onChange({ startSec: Math.max(0, clamped), endSec });
      } else {
        const clamped = Math.max(next, startSec + MIN_DURATION_SEC);
        onChange({ startSec, endSec: Math.min(durationSec, clamped) });
      }
    },
    [endSec, startSec, durationSec, onChange, positionForX],
  );

  const handlePointerUp = useCallback(() => {
    draggingRef.current = null;
  }, []);

  // ─── Render ─────────────────────────────────────────────────────────
  const startPct = durationSec > 0 ? (startSec / durationSec) * 100 : 0;
  const endPct = durationSec > 0 ? (endSec / durationSec) * 100 : 100;

  const placeholders = useMemo(
    () => Array.from({ length: thumbnailCount }, (_, i) => i),
    [thumbnailCount],
  );

  return (
    <div className={cn("flex flex-col gap-2 select-none", className)}>
      <div className="flex items-center justify-between text-[10px] font-mono text-white/70">
        <span>{labels.trimStart}: {startSec.toFixed(1)}s</span>
        <span>{labels.trimEnd}: {endSec.toFixed(1)}s</span>
      </div>
      <div
        ref={trackRef}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        className="relative h-16 rounded-md overflow-hidden bg-black/40 ring-1 ring-white/10"
      >
        {/* Frame strip */}
        <div className="absolute inset-0 flex">
          {(thumbs.length ? thumbs : placeholders).map((entry, i) =>
            typeof entry === "number" ? (
              <div
                key={i}
                className="flex-1 bg-gradient-to-b from-white/5 to-white/10 animate-pulse"
              />
            ) : (
              <div
                key={i}
                className="flex-1 bg-cover bg-center"
                style={{ backgroundImage: `url(${entry.url})` }}
              />
            ),
          )}
        </div>
        {/* Dim out trimmed regions */}
        <div
          className="absolute inset-y-0 left-0 bg-black/60"
          style={{ width: `${startPct}%` }}
          aria-hidden
        />
        <div
          className="absolute inset-y-0 right-0 bg-black/60"
          style={{ width: `${100 - endPct}%` }}
          aria-hidden
        />
        {/* Selection outline */}
        <div
          className="absolute inset-y-0 border-y-2 border-white pointer-events-none"
          style={{ left: `${startPct}%`, right: `${100 - endPct}%` }}
          aria-hidden
        />
        {/* Start handle */}
        <button
          type="button"
          aria-label={labels.trimStart}
          onPointerDown={handlePointerDown("start")}
          className="absolute top-0 bottom-0 w-3 -ml-1.5 grid place-items-center bg-white text-black cursor-ew-resize touch-none"
          style={{ left: `${startPct}%` }}
        >
          <span className="block h-6 w-0.5 bg-black/60" aria-hidden />
        </button>
        {/* End handle */}
        <button
          type="button"
          aria-label={labels.trimEnd}
          onPointerDown={handlePointerDown("end")}
          className="absolute top-0 bottom-0 w-3 -ml-1.5 grid place-items-center bg-white text-black cursor-ew-resize touch-none"
          style={{ left: `${endPct}%` }}
        >
          <span className="block h-6 w-0.5 bg-black/60" aria-hidden />
        </button>
      </div>
    </div>
  );
}

function seekTo(video: HTMLVideoElement, t: number): Promise<void> {
  return new Promise((resolve) => {
    const onSeeked = () => {
      video.removeEventListener("seeked", onSeeked);
      resolve();
    };
    video.addEventListener("seeked", onSeeked, { once: true });
    try {
      video.currentTime = Math.min(t, Math.max(0, video.duration || t));
    } catch {
      video.removeEventListener("seeked", onSeeked);
      resolve();
    }
  });
}
